const admin = require('firebase-admin');

// Manually set project ID if env is missing
const projectId = 'novello-ai';

if (admin.apps.length === 0) {
    admin.initializeApp({
        projectId: projectId
    });
}

const db = admin.firestore();

async function deleteAllProjects() {
    try {
        const snapshot = await db.collection('projects').get();
        if (snapshot.empty) {
            console.log("No projects found to delete.");
            return;
        }

        const batch = db.batch();
        snapshot.forEach(doc => {
            console.log(`Deleting project: ${doc.id} (${doc.data().title})`);
            batch.delete(doc.ref);
        });

        await batch.commit();
        console.log("Successfully deleted all projects.");
    } catch (e) {
        console.error("Error deleting projects:", e);
    }
}

deleteAllProjects();

const admin = require('firebase-admin');
const fs = require('fs');
const path = require('path');

const projectId = 'Mn0bLKLITUqpNrAEvkZM';

if (admin.apps.length === 0) {
    admin.initializeApp({
        projectId: 'novello-ai'
    });
}

const db = admin.firestore();

async function injectChapters() {
    try {
        const snapshot = await db.collection('projects').doc(projectId).collection('chapters').orderBy('order').get();
        const chapters = snapshot.docs.map(doc => ({ id: doc.id, ref: doc.ref }));

        for (let i = 0; i < chapters.length; i++) {
            const filename = `chapter_${i}_long.txt`;
            const filePath = path.join(__dirname, filename);

            if (fs.existsSync(filePath)) {
                console.log(`Injecting ${filename} into DB...`);
                const content = fs.readFileSync(filePath, 'utf8');
                await chapters[i].ref.update({
                    content: content,
                    updatedAt: Date.now()
                });
                console.log(`Success: ${filename}`);
            } else {
                console.log(`File ${filename} not found yet, skipping.`);
            }
        }
        console.log("Injection cycle complete.");
    } catch (e) {
        console.error("Injection error:", e);
    }
}

injectChapters();

