        if (!project || !chapters || !Array.isArray(chapters)) {
            return NextResponse.json({ error: 'Missing or invalid project/chapters data in body' }, { status: 400 });
        }

        // Build HTML for print-to-PDF
        let html = `
<!DOCTYPE html>
