                    font-size: 0.65rem;
                    font-weight: 600;
                    text-transform: uppercase;
                    color: #ef4444;
                    background: rgba(239, 68, 68, 0.1);
                    padding: 2px 6px;
                    border-radius: var(--radius-sm);
                }
