                    </div>
                </div>
            )}
        </>
    );
}

import React, { useState, useEffect } from 'react';
import type { ExportJob } from '@/lib/types';
import { Download, Loader2, XCircle, Mic2, AlertCircle } from 'lucide-react';
import { toast } from 'sonner';
import { useVoices } from '@/lib/hooks/useVoices';
import { AudiobookPlayer } from './AudiobookPlayer';
import { useAuth } from '@/lib/hooks/useAuth';

const JOBS_KEY = (projectId: string) => `novello_audiobook_jobs_${projectId}`;

export function AudiobookExport({ projectId, userId }: { projectId: string; userId: string | undefined; }) {
  const { user } = useAuth();
  const { allVoices, loading: voicesLoading } = useVoices(userId);
  const [jobs, setJobs] = useState<ExportJob[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedVoice, setSelectedVoice] = useState<string>('');
  const [selectedDialogueVoice, setSelectedDialogueVoice] = useState<string>('');
  const [bitrateKbps, setBitrateKbps] = useState<number>(64);
  const [pauseDurationMs, setPauseDurationMs] = useState<number>(1000);
  const [isGenerating, setIsGenerating] = useState(false);

  useEffect(() => {
    if (!selectedVoice && allVoices.length > 0) {
      setSelectedVoice(allVoices[0].id);
    }
  }, [allVoices, selectedVoice]);

  // Load jobs from localStorage
  useEffect(() => {
    if (!projectId) return;
    try {
      const stored = localStorage.getItem(JOBS_KEY(projectId));
      setJobs(stored ? JSON.parse(stored) : []);
    } catch {
      setJobs([]);
    } finally {
      setLoading(false);
    }
  }, [projectId]);

  const handleGenerate = async () => {
    setIsGenerating(true);
    try {
      const token = user?.uid ?? 'local';

      // Fetch project title + chapters from IndexedDB
      const { getProject, getChapters } = await import('@/lib/local-db');
      const [project, chapters] = await Promise.all([
        getProject(projectId),
        getChapters(projectId),
      ]);

      if (!project) throw new Error('Project not found in local database');
      if (!chapters || chapters.length === 0) throw new Error('No chapters to generate audio for');

      const sortedChapters = [...chapters].sort((a, b) => a.order - b.order).map(c => ({
        id: c.id,
        title: c.title,
        content: c.content,
        order: c.order,
      }));

      // Create a pending job record immediately
      const tempJobId = `local-${Date.now()}`;
      const settings = { 
        voiceId: selectedVoice, 
        dialogueVoiceId: selectedDialogueVoice || undefined,
        language: 'en', 
        speed: 1, 
        pauseDurationMs, 
        bitrateKbps 
      };

      const pendingJob: ExportJob = {
        id: tempJobId,
        projectId,
        userId: userId ?? 'local',
        type: 'audiobook',
        status: 'processing',
        progress: { currentChapter: 0, totalChapters: sortedChapters.length, percentComplete: 0, stage: 'cleaning' },
        formats: {},
        settings,
        createdAt: Date.now(),
        updatedAt: Date.now(),
      };
      setJobs(prev => [pendingJob, ...prev]);

      const res = await fetch('/api/ai/audiobook', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({
          projectTitle: project.title,
          chapters: sortedChapters,
          settings,
        }),
      });

      if (!res.ok || !res.body) {
        const data = await res.json().catch(() => ({ error: 'Unknown error' }));
        throw new Error(data.error || 'Failed to start audiobook generation');
      }

      // Parse SSE stream
      const reader = res.body.getReader();
      const decoder = new TextDecoder();
      let exportId = tempJobId;
      let buffer = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n\n');
        buffer = lines.pop() ?? '';

        for (const chunk of lines) {
          const dataLine = chunk.replace(/^data:\s*/, '').trim();
          if (!dataLine) continue;
          try {
            const event = JSON.parse(dataLine);

            if (event.type === 'started') {
              exportId = event.exportId;
            }

            setJobs(prev => prev.map(j => j.id === tempJobId ? {
              ...j,
              id: exportId,
              status: event.type === 'complete' ? 'completed' : event.type === 'error' ? 'failed' : 'processing',
              progress: {
                currentChapter: event.currentChapter ?? 0,
                totalChapters: event.totalChapters ?? sortedChapters.length,
                percentComplete: event.percentComplete ?? 0,
                stage: event.stage ?? 'tts',
              },
              formats: event.downloadUrl ? { m4b: { path: event.downloadUrl, sizeBytes: 0, durationMs: (event.durationSeconds ?? 0) * 1000, codec: 'aac', bitrateKbps, channels: 1, sampleRate: 22050 } } : j.formats,
              error: event.type === 'error' ? event.message : undefined,
              updatedAt: Date.now(),
            } : j));

            if (event.type === 'complete') {
              toast.success('🎧 Audiobook generated!');
            }
            if (event.type === 'error') {
              toast.error(`Generation failed: ${event.message}`);
            }
          } catch { /* skip malformed events */ }
        }
      }

      // Persist final jobs list to localStorage
      setJobs(prev => {
        localStorage.setItem(JOBS_KEY(projectId), JSON.stringify(prev));
        return prev;
      });
    } catch (err: any) {
      toast.error(err.message);
      setJobs(prev => prev.filter(j => j.status !== 'processing'));
    } finally {
      setIsGenerating(false);
    }
  };


  const handleCancel = async (exportId: string) => {
    try {
      const token = user?.uid ?? 'local';
      const res = await fetch('/api/ai/audiobook/cancel', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({ exportId }),
      });

      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error || 'Failed to cancel job');
      }
      toast.success('Job cancelled');
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  return (
    <div className="ab-export-container">
      <style>{`
        .ab-ex-section { background: var(--surface-secondary); padding: 24px; border-radius: 12px; border: 1px solid var(--border); margin-bottom: 24px; }
        .ab-ex-title { font-size: 1.25rem; font-weight: 700; margin-bottom: 16px; color: var(--text-primary); }
        .ab-ex-p { color: var(--text-secondary); margin-bottom: 20px; font-size: 0.95rem; }
        .ab-ex-select { background: var(--surface-primary); border: 1px solid var(--border); color: var(--text-primary); padding: 10px 14px; border-radius: 8px; width: 100%; max-width: 400px; margin-bottom: 20px; font-size: 0.95rem; }
        .ab-ex-generate-btn { display: inline-flex; align-items: center; gap: 8px; background: var(--accent-warm); color: white; border: none; padding: 12px 24px; border-radius: 8px; font-weight: 600; cursor: pointer; transition: opacity 0.2s; }
        .ab-ex-generate-btn:hover { opacity: 0.9; }
        .ab-ex-generate-btn:disabled { opacity: 0.5; cursor: not-allowed; }
        .ab-spin { animation: spin 1s linear infinite; }
        @keyframes spin { to { transform: rotate(360deg); } }

        .ab-ex-job-card { background: var(--surface-tertiary); border: 1px solid var(--border); padding: 16px; border-radius: 8px; margin-bottom: 12px; }
        .ab-ex-job-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 12px; }
        .ab-ex-job-title { font-weight: 600; color: var(--text-primary); display: flex; align-items: center; gap: 8px; }
        .ab-ex-status { padding: 4px 8px; border-radius: 4px; font-size: 0.8rem; font-weight: 600; text-transform: uppercase; }
        .st-queued { background: rgba(255,165,0,0.1); color: #ffa500; }
        .st-processing { background: rgba(56,189,248,0.1); color: #38bdf8; }
        .st-completed { background: rgba(16,185,129,0.1); color: #10b981; }
        .st-failed { background: rgba(239,68,68,0.1); color: #ef4444; }

        .ab-ex-progress-wrap { background: var(--surface-primary); height: 8px; border-radius: 4px; overflow: hidden; margin-bottom: 8px; }
        .ab-ex-progress-fill { background: var(--accent-warm); height: 100%; transition: width 0.3s ease; }
        .ab-ex-progress-text { font-size: 0.85rem; color: var(--text-secondary); display: flex; justify-content: space-between;}

        .ab-ex-job-actions { display: flex; gap: 12px; margin-top: 16px; }
        .ab-ex-btn-sm { padding: 6px 12px; border-radius: 6px; font-size: 0.85rem; font-weight: 600; display: inline-flex; align-items: center; gap: 6px; cursor: pointer; border: 1px solid var(--border); background: var(--surface-secondary); color: var(--text-primary); text-decoration: none;}
        .ab-ex-btn-sm:hover { background: var(--surface-primary); }
        .ab-ex-btn-cancel { color: #ef4444; }
      `}</style>

      <div className="ab-ex-section">
        <h2 className="ab-ex-title">Export Full Audiobook</h2>
        <p className="ab-ex-p">Generate a single, beautifully mastered MP3 of your entire manuscript to download.</p>

        {voicesLoading ? (
          <div style={{ padding: '10px 14px', marginBottom: 20 }}>
            <Loader2 size={16} className="ab-spin" /> Loading Library...
          </div>
        ) : (
          <div style={{ display: 'flex', gap: '16px', marginBottom: '20px', maxWidth: '400px' }}>
            <div style={{ flex: 1 }}>
              <label style={{ display: 'block', fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: '8px', fontWeight: 600 }}>Narrator Voice</label>
              <select className="ab-ex-select" style={{ marginBottom: 0, width: '100%' }} value={selectedVoice} onChange={(e) => setSelectedVoice(e.target.value)}>
                {allVoices.map(v => (
                  <option key={v.id} value={v.id}>
                    {v.displayName} {v.isBuiltin ? '' : '(Custom)'}
                  </option>
                ))}
              </select>
            </div>
            <div style={{ flex: 1 }}>
              <label style={{ display: 'block', fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: '8px', fontWeight: 600 }}>Dialogue Voice (Optional)</label>
              <select className="ab-ex-select" style={{ marginBottom: 0, width: '100%' }} value={selectedDialogueVoice} onChange={(e) => setSelectedDialogueVoice(e.target.value)}>
                <option value="">Same as Narrator</option>
                {allVoices.map(v => (
                  <option key={`dialogue-${v.id}`} value={v.id}>
                    {v.displayName} {v.isBuiltin ? '' : '(Custom)'}
                  </option>
                ))}
              </select>
            </div>
          </div>
        )}

        <div style={{ display: 'flex', gap: '16px', marginBottom: '20px', maxWidth: '400px' }}>
          <div style={{ flex: 1 }}>
            <label style={{ display: 'block', fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: '8px', fontWeight: 600 }}>Audio Quality (Bitrate)</label>
            <select className="ab-ex-select" style={{ marginBottom: 0, width: '100%' }} value={bitrateKbps} onChange={(e) => setBitrateKbps(Number(e.target.value))}>
              <option value={32}>32 kbps (Smallest file)</option>
              <option value={64}>64 kbps (Standard Audiobook)</option>
              <option value={128}>128 kbps (High Quality)</option>
              <option value={192}>192 kbps (Ultra Quality)</option>
            </select>
          </div>
          <div style={{ flex: 1 }}>
            <label style={{ display: 'block', fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: '8px', fontWeight: 600 }}>Chapter Pause Gap</label>
            <select className="ab-ex-select" style={{ marginBottom: 0, width: '100%' }} value={pauseDurationMs} onChange={(e) => setPauseDurationMs(Number(e.target.value))}>
              <option value={500}>0.5 seconds</option>
              <option value={1000}>1 second (Standard)</option>
              <option value={2000}>2 seconds</option>
              <option value={3000}>3 seconds</option>
            </select>
          </div>
        </div>

        <button className="ab-ex-generate-btn" onClick={handleGenerate} disabled={isGenerating}>
          {isGenerating ? <Loader2 size={18} className="ab-spin" /> : <Mic2 size={18} />}
          {isGenerating ? 'Starting...' : 'Generate Audiobook'}
        </button>
      </div>

      <div className="ab-ex-section">
        <h2 className="ab-ex-title">Export History</h2>
        {loading && <Loader2 size={24} className="ab-spin" />}
        {!loading && jobs.length === 0 && <p className="ab-ex-p">No export jobs yet.</p>}

        {jobs.map(job => (
          <div key={job.id} className="ab-ex-job-card">
            <div className="ab-ex-job-header">
              <div className="ab-ex-job-title">
                Audiobook Generation
                <span className={`ab-ex-status st-${job.status}`}>{job.status}</span>
              </div>
              <div className="ab-ex-job-date">
                {job.createdAt ? new Date(job.createdAt as unknown as number).toLocaleDateString() : ''}
              </div>
            </div>

            {job.status === 'processing' || job.status === 'queued' ? (
              <>
                <div className="ab-ex-progress-wrap">
                  <div className="ab-ex-progress-fill" style={{ width: `${job.progress?.percentComplete || 0}%` }} />
                </div>
                <div className="ab-ex-progress-text">
                  <span>{job.progress?.stage === 'tts' ? `Generating Chapter ${job.progress.currentChapter} of ${job.progress.totalChapters}` : job.progress?.stage}</span>
                  <span>{job.progress?.percentComplete || 0}%</span>
                </div>
                <div className="ab-ex-job-actions">
                  <button className="ab-ex-btn-sm ab-ex-btn-cancel" onClick={() => handleCancel(job.id)}>
                    <XCircle size={14} /> Cancel
                  </button>
                </div>
              </>
            ) : job.status === 'completed' ? (
              <div className="ab-ex-player-wrap">
                <div style={{ marginBottom: 16 }}>
                  <AudiobookPlayer exportJob={job} userId={userId} />
                </div>
                <div className="ab-ex-job-actions">
                  {job.formats?.m4b?.path && (
                    <a href={job.formats.m4b.path} target="_blank" rel="noopener noreferrer" className="ab-ex-btn-sm" download>
                      <Download size={14} /> Download M4B (Apple Books)
                    </a>
                  )}
                  {job.formats?.mp3 && (
                    <a href={job.formats.mp3} target="_blank" rel="noopener noreferrer" className="ab-ex-btn-sm" download>
                      <Download size={14} /> Download MP3
                    </a>
                  )}
                  {job.formats?.wav && (
                    <a href={job.formats.wav} target="_blank" rel="noopener noreferrer" className="ab-ex-btn-sm" download>
                      <Download size={14} /> Download WAV (Lossless)
                    </a>
                  )}
                </div>
              </div>
            ) : job.status === 'failed' ? (
              <div className="ab-ex-progress-text" style={{ color: '#ef4444' }}>
                <AlertCircle size={14} style={{ display: 'inline', marginRight: 4 }} />
                {job.error || 'Unknown error occurred.'}
              </div>
            ) : null}
          </div>
        ))}
      </div>
    </div>
  );
}

import { useState, useRef, useEffect } from 'react';
import { Play, Pause, SkipBack, SkipForward, BookmarkPlus, X, List, Bookmark as BookmarkIcon } from 'lucide-react';
import type { ExportJob } from '@/lib/types';
import { usePlaybackSync } from '@/lib/hooks/usePlaybackSync';

interface AudiobookPlayerProps {
    exportJob: ExportJob;
    userId: string | undefined;
}

function formatTime(ms: number) {
    const totalSeconds = Math.floor(ms / 1000);
    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds % 3600) / 60);
    const seconds = totalSeconds % 60;
    if (hours > 0) {
        return `${hours}:${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
    }
    return `${minutes}:${seconds.toString().padStart(2, '0')}`;
}

export function AudiobookPlayer({ exportJob, userId }: AudiobookPlayerProps) {
    const audioRef = useRef<HTMLAudioElement | null>(null);
    const [isPlaying, setIsPlaying] = useState(false);
    const [currentTimeMs, setCurrentTimeMs] = useState(0);
    const [volume, setVolume] = useState(1);
    const [showTabs, setShowTabs] = useState<'chapters' | 'bookmarks' | null>(null);

    // Safety destructure from export object
    const m4bMeta = exportJob.formats?.m4b;
    const mp3Url = exportJob.formats?.mp3;
    const chapters = exportJob.chapters || [];
    const bookMeta = exportJob.bookMeta || { title: 'Audiobook', author: 'Author', coverAssetRef: undefined };
    const durationMs = m4bMeta?.durationMs || 1; // Fallback to avoid div by 0

    const {
        initialPositionMs,
        initialSpeed,
        bookmarks,
        syncPosition,
        addBookmark,
        removeBookmark
    } = usePlaybackSync(userId, exportJob.id);

    // Speed controls
    const [speed, setSpeed] = useState(initialSpeed);
    const speedOptions = [0.75, 1, 1.25, 1.5, 2.0];

    // Load initial position
    const [hasLoaded, setHasLoaded] = useState(false);
    useEffect(() => {
        if (!hasLoaded && audioRef.current && initialPositionMs > 0) {
            audioRef.current.currentTime = initialPositionMs / 1000;
            setCurrentTimeMs(initialPositionMs);
            setHasLoaded(true);
        }
    }, [initialPositionMs, hasLoaded]);

    useEffect(() => {
        if (audioRef.current) {
            audioRef.current.playbackRate = speed;
        }
    }, [speed]);

    const handleTimeUpdate = () => {
        if (!audioRef.current) return;
        const currentMs = audioRef.current.currentTime * 1000;
        setCurrentTimeMs(currentMs);

        // Sync to cloud every ~5s handled smoothly by the hook's internal throttle
        syncPosition(currentMs, speed);
    };

    const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (!audioRef.current) return;
        const newTimeMs = Number(e.target.value);
        audioRef.current.currentTime = newTimeMs / 1000;
        setCurrentTimeMs(newTimeMs);
        syncPosition(newTimeMs, speed, true);
    };

    const jumpFixed = (offsetSec: number) => {
        if (!audioRef.current) return;
        let newTimeMs = (audioRef.current.currentTime + offsetSec) * 1000;
        newTimeMs = Math.max(0, Math.min(newTimeMs, durationMs));
        audioRef.current.currentTime = newTimeMs / 1000;
        setCurrentTimeMs(newTimeMs);
        syncPosition(newTimeMs, speed, true);
    };

    const jumpToTime = (timeMs: number) => {
        if (!audioRef.current) return;
        audioRef.current.currentTime = timeMs / 1000;
        setCurrentTimeMs(timeMs);
        syncPosition(timeMs, speed, true);
        if (!isPlaying) {
            audioRef.current.play();
            setIsPlaying(true);
        }
    };

    const togglePlay = () => {
        if (!audioRef.current) return;
        if (isPlaying) {
            audioRef.current.pause();
            syncPosition(currentTimeMs, speed, true);
        } else {
            audioRef.current.play();
        }
        setIsPlaying(!isPlaying);
    };

    const handleAddBookmark = () => {
        const title = prompt("Bookmark Name:", `Bookmark at ${formatTime(currentTimeMs)}`);
        if (title) {
            addBookmark(currentTimeMs, title);
        }
    };

    if (!mp3Url) return null;

    // Find current chapter
    const activeChapter = chapters.find(c => currentTimeMs >= c.startMs && currentTimeMs <= c.endMs);

    return (
        <div className="audiobook-player">
            <audio
                ref={audioRef}
                src={mp3Url}
                onTimeUpdate={handleTimeUpdate}
                onEnded={() => setIsPlaying(false)}
            />

            <div className="ap-cover-area">
                {bookMeta.coverAssetRef ? (
                    <img src={bookMeta.coverAssetRef} alt="Cover" className="ap-cover" crossOrigin="anonymous" />
                ) : (
                    <div className="ap-cover-fallback" />
                )}
            </div>

            <div className="ap-controls-area">
                <div className="ap-header">
                    <div>
                        <h4 className="ap-title">{bookMeta.title}</h4>
                        <p className="ap-subtitle">{bookMeta.author}</p>
                        {activeChapter && <p className="ap-chapter">{activeChapter.title}</p>}
                    </div>
                    <div className="ap-tools">
                        <button className={`ap-tool-btn ${showTabs === 'chapters' ? 'active' : ''}`} onClick={() => setShowTabs(showTabs === 'chapters' ? null : 'chapters')}>
                            <List size={16} />
                        </button>
                        <button className={`ap-tool-btn ${showTabs === 'bookmarks' ? 'active' : ''}`} onClick={() => setShowTabs(showTabs === 'bookmarks' ? null : 'bookmarks')}>
                            <BookmarkIcon size={16} />
                        </button>
                    </div>
                </div>

                <div className="ap-progress-row">
                    <span className="ap-time">{formatTime(currentTimeMs)}</span>
                    <input
                        type="range"
                        min={0}
                        max={durationMs}
                        value={currentTimeMs}
                        onChange={handleSeek}
                        className="ap-slider"
                    />
                    <span className="ap-time">{formatTime(durationMs)}</span>
                </div>

                <div className="ap-playback-controls">
                    <button className="ap-speed" onClick={() => {
                        const idx = speedOptions.indexOf(speed);
                        const nextSpeed = speedOptions[(idx + 1) % speedOptions.length];
                        setSpeed(nextSpeed);
                        syncPosition(currentTimeMs, nextSpeed, true);
                    }}>
                        {speed}x
                    </button>

                    <button className="ap-icon-btn" onClick={() => jumpFixed(-15)}>
                        <SkipBack size={24} />
                    </button>

                    <button className="ap-play-btn" onClick={togglePlay}>
                        {isPlaying ? <Pause size={28} /> : <Play size={28} className="play-icon" />}
                    </button>

                    <button className="ap-icon-btn" onClick={() => jumpFixed(15)}>
                        <SkipForward size={24} />
                    </button>

                    <button className="ap-icon-btn ap-bookmark-btn" onClick={handleAddBookmark}>
                        <BookmarkPlus size={20} />
                    </button>
                </div>
            </div>

            {/* Slide-out Panels */}
            {showTabs === 'chapters' && (
                <div className="ap-panel">
                    <div className="ap-panel-header">
                        <h5>Chapters</h5>
                        <button onClick={() => setShowTabs(null)}><X size={16} /></button>
                    </div>
                    <div className="ap-list">
                        {chapters.map(c => (
                            <button
                                key={c.chapterId}
                                className={`ap-list-item ${activeChapter?.chapterId === c.chapterId ? 'active' : ''}`}
                                onClick={() => jumpToTime(c.startMs)}
                            >
                                <span>{c.title}</span>
                                <span>{formatTime(c.startMs)}</span>
                            </button>
                        ))}
                    </div>
                </div>
            )}

            {showTabs === 'bookmarks' && (
                <div className="ap-panel">
                    <div className="ap-panel-header">
                        <h5>Bookmarks</h5>
                        <button onClick={() => setShowTabs(null)}><X size={16} /></button>
                    </div>
                    <div className="ap-list">
                        {bookmarks.length === 0 ? <p className="ap-empty">No bookmarks yet.</p> : bookmarks.map(b => (
                            <div key={b.id} className="ap-list-row">
                                <button
                                    className="ap-list-item"
                                    onClick={() => jumpToTime(b.positionMs)}
                                    style={{ flex: 1 }}
                                >
                                    <span>{b.label}</span>
                                    <span>{formatTime(b.positionMs)}</span>
                                </button>
                                <button className="ap-delete-btn" onClick={() => removeBookmark(b.id)}>
                                    <X size={14} />
                                </button>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            <style jsx>{`
