'use client';

import { ContinuityAlert } from '@/lib/types';
import { Sheet } from '@/components/ui/Sheet';
import { AlertTriangle, Clock, MapPin, User, X, CheckCircle, ShieldAlert } from 'lucide-react';
import { Button } from '@/components/ui/Button';

interface AlertsPanelProps {
    isOpen: boolean;
    onClose: () => void;
    alerts: ContinuityAlert[];
    checking: boolean;
    onDismiss: (id: string) => void;
    onCheckNow: () => void;
}

export function AlertsPanel({
    isOpen,
    onClose,
    alerts,
    checking,
    onDismiss,
    onCheckNow
}: AlertsPanelProps) {
    const getIcon = (type: ContinuityAlert['type']) => {
        switch (type) {
            case 'timeline': return <Clock size={16} className="text-blue-500" />;
            case 'characterAttribute': return <User size={16} className="text-purple-500" />;
            case 'settingDetail': return <MapPin size={16} className="text-green-500" />;
            default: return <AlertTriangle size={16} className="text-orange-500" />;
        }
    };

    const getSeverityColor = (severity: ContinuityAlert['severity']) => {
        if (severity === 'critical') {
            return {
                border: '1px solid rgba(244, 63, 94, 0.2)',
                background: 'rgba(244, 63, 94, 0.05)',
                glow: '0 0 15px rgba(244, 63, 94, 0.1)'
            };
        }
        return {
            border: '1px solid rgba(184, 134, 11, 0.2)',
            background: 'rgba(184, 134, 11, 0.03)',
            glow: '0 0 15px rgba(184, 134, 11, 0.05)'
        };
    };

    return (
        <Sheet isOpen={isOpen} onClose={onClose} title="Continuity Alerts">
            <div className="p-4 space-y-4">
                <div className="flex justify-between items-center mb-6">
                    <p className="text-sm text-[var(--text-secondary)]">
                        AI-detected continuity issues.
                    </p>
                    <Button
                        onClick={onCheckNow}
                        size="sm"
                        disabled={checking}
                    >
                        {checking ? 'Scanning...' : 'Scan Now'}
                    </Button>
                </div>

                {checking && (
                    <div className="flex flex-col items-center justify-center py-12 text-[var(--text-tertiary)]">
                        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-[var(--accent)] mb-4"></div>
                        <p className="text-sm">Analyzing timeline & facts...</p>
                    </div>
                )}

                {!checking && alerts.length === 0 && (
                    <div className="text-center p-8 text-[var(--text-secondary)] bg-[var(--surface-secondary)] rounded-lg">
                        <ShieldAlert className="w-8 h-8 mx-auto mb-2 opacity-50" />
                        <p>No issues detected.</p>
                        <p className="text-xs mt-2 text-[var(--text-tertiary)]">Run a scan to check for contradictions.</p>
                    </div>
                )}

                <div className="space-y-3">
                    {alerts.map((alert) => {
                        const colors = getSeverityColor(alert.severity);
                        return (
                            <div
                                key={alert.id}
                                className="p-4 rounded-lg transition-all animate-slide-up"
                                style={{
                                    border: colors.border,
                                    background: colors.background,
                                    boxShadow: colors.glow
                                }}
                            >
                                <div className="flex justify-between items-start mb-2">
                                    <div className="flex items-center gap-2">
                                        {getIcon(alert.type)}
                                        <span className="text-[10px] font-bold uppercase tracking-widest opacity-60" style={{ color: 'var(--text-tertiary)' }}>
                                            {alert.type.replace(/([A-Z])/g, ' $1').trim()}
                                        </span>
                                    </div>
                                    <button
                                        onClick={() => onDismiss(alert.id)}
                                        className="text-[var(--text-tertiary)] hover:text-[var(--text-primary)] transition-colors p-1"
                                    >
                                        <X size={14} />
                                    </button>
                                </div>

                                <p className="text-sm font-medium mb-2 leading-relaxed" style={{ color: 'var(--text-primary)' }}>
                                    {alert.message}
                                </p>

                                {alert.flaggedExcerpt && (
                                    <div className="bg-black/5 dark:bg-white/5 p-2 rounded text-[11px] italic mb-2 border border-black/5 dark:border-white/5" style={{ color: 'var(--text-secondary)' }}>
                                        "{alert.flaggedExcerpt}"
                                    </div>
                                )}

                                <div className="flex justify-end gap-2 mt-4">
                                    <Button
                                        size="sm"
                                        variant="ghost"
                                        className="h-7 text-[10px] uppercase tracking-wider font-bold"
                                        onClick={() => onDismiss(alert.id)}
                                    >
                                        Dismiss
                                    </Button>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </Sheet>
    );
}

'use client';

import { useState } from 'react';
import { useAuth } from '@/lib/hooks/useAuth';
import { saveChapterCritique, getCritiqueForChapter } from '@/lib/local-db';
import { ChapterCritique } from '@/lib/types';
import { Sparkles, ChevronDown, ChevronUp, Star, Loader2 } from 'lucide-react';
import { toast } from 'sonner';

function ScoreBar({ label, score, feedback, expanded }: { label: string; score: number; feedback: string; expanded: boolean }) {
    const color = score >= 8 ? 'var(--success, #16a34a)' : score >= 6 ? 'var(--accent)' : score >= 4 ? 'var(--warning, #d97706)' : 'var(--danger, #dc2626)';
    return (
        <div style={{ marginBottom: 10 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
                <span style={{ fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-secondary)' }}>{label}</span>
                <span style={{ fontSize: '0.85rem', fontWeight: 800, color }}>{score}/10</span>
            </div>
            <div style={{ height: 4, background: 'var(--border)', borderRadius: 4 }}>
                <div style={{ height: '100%', width: `${score * 10}%`, background: color, borderRadius: 4, transition: 'width 0.5s ease' }} />
            </div>
            {expanded && feedback && (
                <p style={{ fontSize: '0.75rem', color: 'var(--text-tertiary)', marginTop: 6, lineHeight: 1.5 }}>{feedback}</p>
            )}
        </div>
    );
}

interface CritiquePanelProps {
    chapterId: string;
    chapterTitle: string;
    chapterContent: string;
    projectId: string;
    context?: string;
}

export function CritiquePanel({ chapterId, chapterTitle, chapterContent, projectId, context }: CritiquePanelProps) {
    const { user } = useAuth();
    const [critique, setCritique] = useState<ChapterCritique | null>(null);
    const [loading, setLoading] = useState(false);
    const [expanded, setExpanded] = useState(false);
    const [detailsOpen, setDetailsOpen] = useState(false);

    const runCritique = async () => {
        if (!user?.uid) { toast.error('Not authenticated'); return; }
        setLoading(true);
        try {
            // Check cache first
            const cached = await getCritiqueForChapter(chapterId);
            if (cached && Date.now() - cached.createdAt < 3600_000) {
                setCritique(cached);
                setExpanded(true);
                setLoading(false);
                return;
            }

            const token = '';
            const res = await fetch('/api/ai/critique', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
                body: JSON.stringify({ chapterId, chapterTitle, chapterContent, context }),
            });
            if (!res.ok) throw new Error('Critique request failed');
            const data = await res.json();
            const c: ChapterCritique = {
                id: `${chapterId}-${Date.now()}`,
                chapterId,
                projectId,
                userId: user.uid,
                overallScore: data.overallScore || 5,
                pacing: data.pacing || { score: 5, feedback: '' },
                tension: data.tension || { score: 5, feedback: '' },
                characterVoice: data.characterVoice || { score: 5, feedback: '' },
                hookStrength: data.hookStrength || { score: 5, feedback: '' },
                highlights: data.highlights || [],
                suggestions: data.suggestions || [],
                createdAt: Date.now(),
            };
            await saveChapterCritique(c);
            setCritique(c);
            setExpanded(true);
        } catch (e) {
            toast.error('Critique failed — is Ollama running?');
        } finally {
            setLoading(false);
        }
    };

    const overallColor = critique ? (critique.overallScore >= 8 ? '#16a34a' : critique.overallScore >= 6 ? 'var(--accent)' : critique.overallScore >= 4 ? '#d97706' : '#dc2626') : 'var(--text-tertiary)';

    return (
        <div style={{ padding: '0.75rem', borderTop: '1px solid var(--border)' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: expanded ? 12 : 0 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                    <Sparkles size={14} color="var(--accent)" />
                    <span style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--text-secondary)', textTransform: 'uppercase', letterSpacing: '0.04em' }}>AI Beta Reader</span>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                    {critique && (
                        <span style={{ fontSize: '0.85rem', fontWeight: 800, color: overallColor }}>
                            ⭐ {critique.overallScore}/10
                        </span>
                    )}
                    <button
                        onClick={expanded ? () => setExpanded(false) : runCritique}
                        disabled={loading}
                        style={{ fontSize: '0.72rem', fontWeight: 600, color: 'var(--accent)', background: 'rgba(var(--accent-rgb, 99,102,241), 0.1)', border: 'none', borderRadius: 6, padding: '4px 10px', cursor: loading ? 'wait' : 'pointer', display: 'flex', alignItems: 'center', gap: 4 }}
                    >
                        {loading ? <><Loader2 size={12} style={{ animation: 'spin 1s linear infinite' }} /> Analyzing...</> : expanded ? 'Hide' : critique ? 'Show' : 'Critique'}
                    </button>
                </div>
            </div>

            {expanded && critique && (
                <div>
                    <ScoreBar label="Pacing" score={critique.pacing.score} feedback={critique.pacing.feedback} expanded={detailsOpen} />
                    <ScoreBar label="Tension" score={critique.tension.score} feedback={critique.tension.feedback} expanded={detailsOpen} />
                    <ScoreBar label="Character Voice" score={critique.characterVoice.score} feedback={critique.characterVoice.feedback} expanded={detailsOpen} />
                    <ScoreBar label="Hook Strength" score={critique.hookStrength.score} feedback={critique.hookStrength.feedback} expanded={detailsOpen} />

                    <button
                        onClick={() => setDetailsOpen(!detailsOpen)}
                        style={{ fontSize: '0.72rem', color: 'var(--text-tertiary)', background: 'none', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 4, margin: '8px 0' }}
                    >
                        {detailsOpen ? <ChevronUp size={12} /> : <ChevronDown size={12} />}
                        {detailsOpen ? 'Hide' : 'Show'} detailed feedback
                    </button>

                    {detailsOpen && (
                        <>
                            {critique.highlights.length > 0 && (
                                <div style={{ marginBottom: 10 }}>
                                    <div style={{ fontSize: '0.72rem', fontWeight: 700, color: 'var(--success, #16a34a)', marginBottom: 4 }}>✓ What worked</div>
                                    {critique.highlights.map((h, i) => (
                                        <div key={i} style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', lineHeight: 1.5, marginBottom: 4, paddingLeft: 8, borderLeft: '2px solid var(--success, #16a34a)' }}>{h}</div>
                                    ))}
                                </div>
                            )}
                            {critique.suggestions.length > 0 && (
                                <div>
                                    <div style={{ fontSize: '0.72rem', fontWeight: 700, color: 'var(--warning, #d97706)', marginBottom: 4 }}>↑ Top improvements</div>
                                    {critique.suggestions.map((s, i) => (
                                        <div key={i} style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', lineHeight: 1.5, marginBottom: 4, paddingLeft: 8, borderLeft: '2px solid var(--warning, #d97706)' }}>
                                            {i + 1}. {s}
                                        </div>
                                    ))}
                                </div>
                            )}
                        </>
                    )}

                    <div style={{ fontSize: '0.68rem', color: 'var(--text-tertiary)', marginTop: 8 }}>
                        Cached · <button onClick={runCritique} style={{ background: 'none', border: 'none', color: 'var(--accent)', cursor: 'pointer', fontSize: '0.68rem' }}>Refresh</button>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import { useState, useCallback } from 'react';
import { BubbleMenu } from '@tiptap/react/menus';
import { Editor } from '@tiptap/react';
import { Wand2, Expand, Check, X, Loader2 } from 'lucide-react';
import { useAI } from '@/lib/hooks/useAI';
import { useAuth } from '@/lib/hooks/useAuth';
import { saveVersion } from '@/lib/firestore';
import { toast } from 'sonner';

interface InlineAssistProps {
    editor: Editor;
    rollingContext?: string;
    projectId?: string;
    chapterId?: string;
}

export function InlineAssist({ editor, rollingContext = '', projectId, chapterId }: InlineAssistProps) {
    const { user } = useAuth();
    const { loading, streamedText, streamGenerate, cancelGeneration } = useAI('ollama', '', projectId);
    const [showPreview, setShowPreview] = useState(false);

    const handleAction = useCallback(
        async (action: 'rewrite' | 'expand') => {
            const { from, to } = editor.state.selection;
            const selectedText = editor.state.doc.textBetween(from, to, ' ');
            if (!selectedText.trim()) return;

            setShowPreview(true);
            // Pass the full chapter text for Loom continuity window (up to 20k words downstream)
            const activeChapterText = editor.getText();
            await streamGenerate(selectedText, action, activeChapterText);
        },
        [editor, streamGenerate]
    );

    const handleAccept = useCallback(async () => {
        if (!streamedText) return;
        const { from, to } = editor.state.selection;
        editor
            .chain()
            .focus()
            .deleteRange({ from, to })
            .insertContent(streamedText)
            .run();
        setShowPreview(false);

        // Save version snapshot on AI insert (PRD Section 7.2)
        if (chapterId && user) {
            try {
                const fullContent = editor.getHTML();
                await saveVersion(chapterId, user.uid, fullContent, 'ai-generation');
            } catch (err) {
                console.error('Failed to save AI insert version:', err);
                // Don't block the user flow, just log
            }
        }
    }, [editor, streamedText, chapterId, user]);

    const handleDismiss = useCallback(() => {
        cancelGeneration();
        setShowPreview(false);
    }, [cancelGeneration]);

    return (
        <>
            <BubbleMenu
                editor={editor}
                shouldShow={({ editor: e }: { editor: Editor }) => {
                    const { from, to } = e.state.selection;
                    const text = e.state.doc.textBetween(from, to, ' ');
                    return text.trim().length > 5 && !showPreview;
                }}
            >
                <div
                    className="flex items-center gap-1 px-2 py-1.5 rounded-[var(--radius-lg)] shadow-lg"
                    style={{
                        background: 'rgba(255,255,255,0.92)',
                        backdropFilter: 'blur(20px)',
                        border: '1px solid var(--border)',
                        boxShadow: '0 8px 32px rgba(0,0,0,0.12)',
                    }}
                >
                    <button
                        onClick={() => handleAction('rewrite')}
                        disabled={loading}
                        className="flex items-center gap-1.5 px-3 py-1.5 rounded-[var(--radius-md)] text-xs font-medium transition-all hover:bg-[var(--surface-tertiary)] cursor-pointer"
                        style={{ color: 'var(--accent)' }}
                    >
                        <Wand2 size={13} />
                        Rewrite
                    </button>
                    <div style={{ width: 1, height: 16, background: 'var(--border)' }} />
                    <button
                        onClick={() => handleAction('expand')}
                        disabled={loading}
                        className="flex items-center gap-1.5 px-3 py-1.5 rounded-[var(--radius-md)] text-xs font-medium transition-all hover:bg-[var(--surface-tertiary)] cursor-pointer"
                        style={{ color: 'var(--text-secondary)' }}
                    >
                        <Expand size={13} />
                        Expand
                    </button>
                </div>
            </BubbleMenu>

            {/* Streaming Preview Panel */}
            {showPreview && (
                <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-2xl z-50">
                    <div
                        className="rounded-[var(--radius-lg)] p-5 shadow-xl"
                        style={{
                            background: 'rgba(255,255,255,0.95)',
                            backdropFilter: 'blur(24px)',
                            border: '1px solid var(--border)',
                            boxShadow: '0 12px 48px rgba(0,0,0,0.15)',
                        }}
                    >
                        <div className="flex items-center justify-between mb-3">
                            <span className="flex items-center gap-2 text-xs font-medium" style={{ color: 'var(--accent)' }}>
                                {loading ? (
                                    <>
                                        <Loader2 size={12} className="animate-spin" />
                                        Generating...
                                    </>
                                ) : (
                                    <>
                                        <Wand2 size={12} />
                                        AI Suggestion
                                    </>
                                )}
                            </span>
                            <div className="flex items-center gap-1.5">
                                {!loading && streamedText && (
                                    <button
                                        onClick={handleAccept}
                                        className="flex items-center gap-1 px-3 py-1.5 rounded-[var(--radius-md)] text-xs font-medium text-white transition-all cursor-pointer"
                                        style={{ background: 'var(--accent)' }}
                                    >
                                        <Check size={12} />
                                        Accept
                                    </button>
                                )}
                                <button
                                    onClick={handleDismiss}
                                    className="flex items-center gap-1 px-3 py-1.5 rounded-[var(--radius-md)] text-xs font-medium transition-all hover:bg-[var(--surface-tertiary)] cursor-pointer"
                                    style={{ color: 'var(--text-tertiary)' }}
                                >
                                    <X size={12} />
                                    Dismiss
                                </button>
                            </div>
                        </div>
                        <div
                            className="text-sm leading-relaxed max-h-48 overflow-y-auto"
                            style={{
                                color: 'var(--text-primary)',
                                fontFamily: 'var(--font-serif)',
                            }}
                        >
                            {streamedText || (
                                <span style={{ color: 'var(--text-tertiary)', fontStyle: 'italic' }}>
                                    Waiting for response...
                                </span>
                            )}
                        </div>
                        {rollingContext && (
                            <div className="mt-2 pt-2 border-t" style={{ borderColor: 'var(--border)' }}>
                                <span className="text-[10px]" style={{ color: 'var(--text-tertiary)' }}>
                                    ✦ Context-aware (using {rollingContext.split('\n').length - 1} chapter summaries)
                                </span>
                            </div>
                        )}
                    </div>
                </div>
            )}
        </>
    );
}

import { Extension } from '@tiptap/core';
import { Plugin, PluginKey } from '@tiptap/pm/state';
import { Decoration, DecorationSet } from '@tiptap/pm/view';

// =============================================
// PassiveVoice — Decoration plugin that highlights passive voice constructions
// Pattern: forms of "be" + past participle (ed/en/wn/ght/ung etc.)
// =============================================

const PASSIVE_VOICE_KEY = new PluginKey('passiveVoice');

// Common "be" forms
const BE_FORMS = [
    'am', 'is', 'are', 'was', 'were', 'be', 'been', 'being',
    'get', 'gets', 'got', 'gotten', 'getting',
];

// Past participle endings (heuristic)
const PP_ENDINGS = /(?:ed|en|wn|ght|ung|nt|ck|pt|ft|lt|mn|rn|st)$/i;

// Common irregular past participles
const IRREGULAR_PP = new Set([
    'been', 'born', 'broken', 'chosen', 'done', 'drawn', 'driven',
    'eaten', 'fallen', 'flown', 'forgotten', 'frozen', 'given', 'gone',
    'grown', 'hidden', 'known', 'lain', 'left', 'made', 'paid',
    'ridden', 'risen', 'run', 'seen', 'shaken', 'shown', 'spoken',
    'stolen', 'sworn', 'taken', 'thrown', 'told', 'torn', 'understood',
    'woken', 'worn', 'written', 'built', 'bought', 'brought', 'caught',
    'cut', 'dealt', 'dug', 'fed', 'felt', 'found', 'fought', 'heard',
    'held', 'hit', 'hung', 'hurt', 'kept', 'knelt', 'laid', 'led',
    'lost', 'meant', 'met', 'put', 'read', 'said', 'sat', 'sent',
    'set', 'shot', 'shut', 'slept', 'slid', 'sold', 'sought', 'spent',
    'spun', 'split', 'spread', 'stood', 'struck', 'stuck', 'stung',
    'sung', 'sunk', 'swept', 'swum', 'swung', 'taught', 'thought',
    'wound', 'woven', 'won', 'wept',
]);

function isPastParticiple(word: string): boolean {
    const lower = word.toLowerCase();
    return IRREGULAR_PP.has(lower) || PP_ENDINGS.test(lower);
}

function findPassiveVoice(text: string): Array<{ from: number; to: number }> {
    const matches: Array<{ from: number; to: number }> = [];
    const words = text.split(/(\s+)/);
    let pos = 0;

    for (let i = 0; i < words.length; i++) {
        const word = words[i];
        const lower = word.toLowerCase();

        if (BE_FORMS.includes(lower)) {
            // Look for the next non-whitespace word
            let j = i + 1;
            let nextPos = pos + word.length;
            while (j < words.length && /^\s+$/.test(words[j])) {
                nextPos += words[j].length;
                j++;
            }

            if (j < words.length && isPastParticiple(words[j])) {
                // Mark the entire "be + pp" span
                const matchEnd = nextPos + words[j].length;
                matches.push({ from: pos, to: matchEnd });
            }
        }

        pos += word.length;
    }

    return matches;
}

export interface PassiveVoiceOptions {
    enabled: boolean;
}

export const PassiveVoiceExtension = Extension.create<PassiveVoiceOptions>({
    name: 'passiveVoice',

    addOptions() {
        return { enabled: false };
    },

    addProseMirrorPlugins() {
        const extensionThis = this;
        return [
            new Plugin({
                key: PASSIVE_VOICE_KEY,
                state: {
                    init(_, state) {
                        if (!extensionThis.options.enabled) return DecorationSet.empty;
                        return buildDecorations(state.doc);
                    },
                    apply(tr, oldSet) {
                        if (!extensionThis.options.enabled) return DecorationSet.empty;
                        if (tr.docChanged) {
                            return buildDecorations(tr.doc);
                        }
                        return oldSet;
                    },
                },
                props: {
                    decorations(state) {
                        return this.getState(state) ?? DecorationSet.empty;
                    },
                },
            }),
        ];
    },
});

function buildDecorations(doc: import('@tiptap/pm/model').Node): DecorationSet {
    const decorations: Decoration[] = [];

    doc.descendants((node, pos) => {
        if (!node.isText || !node.text) return;
        const matches = findPassiveVoice(node.text);
        for (const match of matches) {
            decorations.push(
                Decoration.inline(pos + match.from, pos + match.to, {
                    class: 'passive-voice-highlight',
                    style:
                        'background: rgba(245, 158, 11, 0.15); border-bottom: 2px wavy #f59e0b; border-radius: 2px;',
                })
            );
        }
    });

    return DecorationSet.create(doc, decorations);
}

'use client';

import { useMemo } from 'react';
import { analyzeReadability, ReadabilityMetrics } from '@/lib/readability';

interface ProseCoachProps {
    content: string; // HTML content from TipTap
}

function GaugeBar({ value, max, color, label }: { value: number; max: number; color: string; label: string }) {
    const pct = Math.min(100, (value / max) * 100);
    return (
        <div style={{ marginBottom: 12 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4, fontSize: '0.75rem' }}>
                <span style={{ color: 'var(--text-secondary)', fontWeight: 500 }}>{label}</span>
                <span style={{ color, fontWeight: 700 }}>{value}</span>
            </div>
            <div style={{ height: 4, background: 'var(--border)', borderRadius: 4, overflow: 'hidden' }}>
                <div style={{ height: '100%', width: `${pct}%`, background: color, borderRadius: 4, transition: 'width 0.5s ease' }} />
            </div>
        </div>
    );
}

function ScorePill({ label, value, ideal, low, high }: { label: string; value: number; ideal: number; low: number; high: number }) {
    const quality = value >= low && value <= high ? 'good' : value < low ? 'low' : 'high';
    const colors = { good: 'var(--success, #16a34a)', low: 'var(--warning, #d97706)', high: 'var(--danger, #dc2626)' };
    return (
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '6px 0', borderBottom: '1px solid var(--border)' }}>
            <span style={{ fontSize: '0.78rem', color: 'var(--text-secondary)' }}>{label}</span>
            <span style={{
                fontSize: '0.78rem', fontWeight: 700, color: colors[quality],
                background: `${colors[quality]}18`, borderRadius: 6, padding: '2px 8px'
            }}>
                {typeof value === 'number' ? value.toFixed(1) : value}
            </span>
        </div>
    );
}

export function ProseCoach({ content }: ProseCoachProps) {
    const metrics = useMemo(() => analyzeReadability(content), [content]);

    if (!metrics) {
        return (
            <div style={{ padding: '1rem', fontSize: '0.8rem', color: 'var(--text-tertiary)', textAlign: 'center' }}>
                Start writing to see prose metrics
            </div>
        );
    }

    const { fleschKincaid, avgSentenceLength, passiveVoiceCount, adverbCount, wordCount } = metrics;

    // Flesch score quality
    const fleschQuality = fleschKincaid >= 60 ? 'Accessible' : fleschKincaid >= 40 ? 'Moderate' : 'Complex';
    const fleschColor = fleschKincaid >= 60 ? 'var(--success, #16a34a)' : fleschKincaid >= 40 ? 'var(--warning, #d97706)' : 'var(--danger, #dc2626)';

    return (
        <div style={{ padding: '0.75rem', display: 'flex', flexDirection: 'column', gap: 8 }}>
            <div style={{ fontSize: '0.72rem', fontWeight: 700, color: 'var(--text-tertiary)', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 4 }}>
                📊 Prose Coach
            </div>

            {/* Flesch-Kincaid Score */}
            <div style={{ background: 'var(--surface-secondary)', borderRadius: 10, padding: '0.75rem', border: '1px solid var(--border)' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 6 }}>
                    <span style={{ fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-secondary)' }}>Readability</span>
                    <span style={{ fontSize: '0.9rem', fontWeight: 800, color: fleschColor }}>{Math.round(fleschKincaid)}</span>
                </div>
                <div style={{ fontSize: '0.72rem', color: fleschColor, fontWeight: 600, marginBottom: 6 }}>{fleschQuality}</div>
                <div style={{ height: 3, background: 'var(--border)', borderRadius: 4 }}>
                    <div style={{ height: '100%', width: `${Math.min(100, fleschKincaid)}%`, background: fleschColor, borderRadius: 4 }} />
                </div>
                <div style={{ fontSize: '0.68rem', color: 'var(--text-tertiary)', marginTop: 4 }}>
                    60+ accessible · 40–60 moderate · ≤40 literary
                </div>
            </div>

            {/* Prose Metrics */}
            <div style={{ background: 'var(--surface-secondary)', borderRadius: 10, padding: '0.75rem', border: '1px solid var(--border)' }}>
                <ScorePill label="Avg Sentence Length" value={avgSentenceLength} ideal={15} low={8} high={25} />
                <ScorePill label="Passive Voice %" value={passiveVoiceCount} ideal={5} low={0} high={10} />
                <ScorePill label="Adverb Count" value={adverbCount} ideal={3} low={0} high={10} />
            </div>

            {/* Word stats */}
            <div style={{ display: 'flex', gap: 8 }}>
                <div style={{ flex: 1, background: 'var(--surface-secondary)', borderRadius: 8, padding: '0.6rem', border: '1px solid var(--border)', textAlign: 'center' }}>
                    <div style={{ fontSize: '1rem', fontWeight: 800, color: 'var(--accent)' }}>{wordCount.toLocaleString()}</div>
                    <div style={{ fontSize: '0.68rem', color: 'var(--text-tertiary)' }}>words</div>
                </div>
                <div style={{ flex: 1, background: 'var(--surface-secondary)', borderRadius: 8, padding: '0.6rem', border: '1px solid var(--border)', textAlign: 'center' }}>
                    <div style={{ fontSize: '1rem', fontWeight: 800, color: 'var(--text-primary)' }}>{Math.ceil(wordCount / 200)}</div>
                    <div style={{ fontSize: '0.68rem', color: 'var(--text-tertiary)' }}>min read</div>
                </div>
            </div>

            {/* Tips */}
            {passiveVoiceCount > 10 && (
                <div style={{ fontSize: '0.72rem', color: 'var(--warning, #d97706)', background: 'rgba(217,119,6,0.08)', padding: '6px 10px', borderRadius: 8 }}>
                    ⚠ High passive voice — aim for under 10%
                </div>
            )}
            {adverbCount > 15 && (
                <div style={{ fontSize: '0.72rem', color: 'var(--warning, #d97706)', background: 'rgba(217,119,6,0.08)', padding: '6px 10px', borderRadius: 8 }}>
                    ⚠ Many adverbs detected — show, don't modify
                </div>
            )}
            {avgSentenceLength > 30 && (
                <div style={{ fontSize: '0.72rem', color: 'var(--warning, #d97706)', background: 'rgba(217,119,6,0.08)', padding: '6px 10px', borderRadius: 8 }}>
                    ⚠ Long sentences — consider breaking them up
                </div>
            )}
        </div>
    );
}

'use client';

import { WritingSession } from '@/lib/types';
import { useMemo } from 'react';
import { Flame, Calendar, Trophy } from 'lucide-react';

interface StreakCalendarProps {
    sessions: WritingSession[];
    streak: number;
    todayWords: number;
    dailyGoal?: number;
}

function today() { return new Date().toISOString().slice(0, 10); }

function getLast12Weeks(): string[] {
    const dates: string[] = [];
    const d = new Date();
    for (let i = 83; i >= 0; i--) {
        const cursor = new Date(d);
        cursor.setDate(d.getDate() - i);
        dates.push(cursor.toISOString().slice(0, 10));
    }
    return dates; // 84 = 12 weeks
}

function getIntensity(words: number, goal: number): 0 | 1 | 2 | 3 | 4 {
    if (words === 0) return 0;
    if (words < goal * 0.25) return 1;
    if (words < goal * 0.5) return 2;
    if (words < goal) return 3;
    return 4;
}

const INTENSITY_COLORS: Record<0 | 1 | 2 | 3 | 4, string> = {
    0: 'var(--border)',
    1: 'rgba(var(--accent-rgb, 99,102,241), 0.2)',
    2: 'rgba(var(--accent-rgb, 99,102,241), 0.4)',
    3: 'rgba(var(--accent-rgb, 99,102,241), 0.7)',
    4: 'var(--accent)',
};

export function StreakCalendar({ sessions, streak, todayWords, dailyGoal = 500 }: StreakCalendarProps) {
    const sessionMap = useMemo(() => {
        const m: Record<string, number> = {};
        sessions.forEach(s => { m[s.date] = (m[s.date] || 0) + s.wordsWritten; });
        return m;
    }, [sessions]);

    const dates = getLast12Weeks();
    const todayDate = today();

    return (
        <div style={{ padding: '0.75rem', borderTop: '1px solid var(--border)' }}>
            {/* Header stats */}
            <div style={{ display: 'flex', gap: 12, marginBottom: 12 }}>
                <div style={{ flex: 1, background: 'var(--surface-secondary)', borderRadius: 8, padding: '0.5rem', border: '1px solid var(--border)', textAlign: 'center' }}>
                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 4, marginBottom: 2 }}>
                        <Flame size={12} color="#f97316" />
                        <span style={{ fontSize: '1rem', fontWeight: 800, color: streak > 0 ? '#f97316' : 'var(--text-secondary)' }}>{streak}</span>
                    </div>
                    <div style={{ fontSize: '0.65rem', color: 'var(--text-tertiary)' }}>day streak</div>
                </div>
                <div style={{ flex: 1, background: 'var(--surface-secondary)', borderRadius: 8, padding: '0.5rem', border: '1px solid var(--border)', textAlign: 'center' }}>
                    <div style={{ fontSize: '0.95rem', fontWeight: 800, color: 'var(--accent)', marginBottom: 2 }}>{todayWords.toLocaleString()}</div>
                    <div style={{ fontSize: '0.65rem', color: 'var(--text-tertiary)' }}>today</div>
                </div>
                <div style={{ flex: 1, background: 'var(--surface-secondary)', borderRadius: 8, padding: '0.5rem', border: '1px solid var(--border)', textAlign: 'center' }}>
                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 4, marginBottom: 2 }}>
                        <Trophy size={12} color="var(--accent)" />
                        <span style={{ fontSize: '0.95rem', fontWeight: 800, color: 'var(--text-primary)' }}>{sessions.length}</span>
                    </div>
                    <div style={{ fontSize: '0.65rem', color: 'var(--text-tertiary)' }}>active days</div>
                </div>
            </div>

            {/* Today's progress bar */}
            <div style={{ marginBottom: 12 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.7rem', color: 'var(--text-tertiary)', marginBottom: 4 }}>
                    <span>Today's Goal</span>
                    <span style={{ fontWeight: 600, color: todayWords >= dailyGoal ? 'var(--success, #16a34a)' : 'var(--text-secondary)' }}>
                        {todayWords} / {dailyGoal} words
                    </span>
                </div>
                <div style={{ height: 6, background: 'var(--border)', borderRadius: 4, overflow: 'hidden' }}>
                    <div style={{
                        height: '100%',
                        width: `${Math.min(100, (todayWords / dailyGoal) * 100)}%`,
                        background: todayWords >= dailyGoal ? 'var(--success, #16a34a)' : 'var(--accent)',
                        borderRadius: 4,
                        transition: 'width 0.5s ease',
                    }} />
                </div>
            </div>

            {/* Contribution-style heatmap grid */}
            <div>
                <div style={{ fontSize: '0.68rem', color: 'var(--text-tertiary)', marginBottom: 6, display: 'flex', alignItems: 'center', gap: 4 }}>
                    <Calendar size={10} /> 12-week writing activity
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(12, 1fr)', gap: 2 }}>
                    {Array.from({ length: 12 }, (_, week) => (
                        <div key={week} style={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
                            {dates.slice(week * 7, week * 7 + 7).map(date => {
                                const words = sessionMap[date] || 0;
                                const intensity = getIntensity(words, dailyGoal);
                                const isToday = date === todayDate;
                                return (
                                    <div
                                        key={date}
                                        title={`${date}: ${words.toLocaleString()} words`}
                                        style={{
                                            width: '100%',
                                            aspectRatio: '1',
                                            borderRadius: 2,
                                            background: INTENSITY_COLORS[intensity],
                                            outline: isToday ? '1px solid var(--accent)' : 'none',
                                        }}
                                    />
                                );
                            })}
                        </div>
                    ))}
                </div>
                <div style={{ display: 'flex', justifyContent: 'flex-end', alignItems: 'center', gap: 4, marginTop: 6 }}>
                    <span style={{ fontSize: '0.6rem', color: 'var(--text-tertiary)' }}>Less</span>
                    {([0, 1, 2, 3, 4] as const).map(i => (
                        <div key={i} style={{ width: 8, height: 8, borderRadius: 2, background: INTENSITY_COLORS[i] }} />
                    ))}
                    <span style={{ fontSize: '0.6rem', color: 'var(--text-tertiary)' }}>More</span>
                </div>
            </div>
        </div>
    );
}

