                    align-items: baseline;
                    margin-bottom: 6px;
                }
                .setup-stat-name {
                    font-size: 0.78rem;
                    font-weight: 600;
                    color: var(--text-secondary);
                }
                .setup-stat-value {
                    font-size: 0.85rem;
                    font-weight: 700;
                    color: var(--text-primary);
                }
                .setup-stat-target {
                    font-weight: 400;
                    color: var(--text-tertiary);
                }
                .setup-progress-track {
                    height: 7px;
                    border-radius: 4px;
                    background: var(--surface-elevated);
                    overflow: hidden;
                    margin-bottom: 4px;
                }
                .setup-progress-fill {
                    height: 100%;
                    border-radius: 4px;
                    transition: width 0.4s ease;
                }
                .setup-pct {
                    font-size: 0.65rem;
                    color: var(--text-tertiary);
                }

                /* ── Quick nav ── */
                .setup-nav-links {
                    display: flex;
                    flex-direction: column;
                    gap: 4px;
                }
                .setup-nav-link {
                    display: flex;
                    align-items: center;
                    justify-content: space-between;
                    padding: 9px 12px;
                    border-radius: var(--radius-md);
                    border: 1px solid var(--border);
                    background: var(--surface-tertiary);
                    color: var(--text-secondary);
                    font-size: 0.8rem;
                    font-weight: 500;
                    cursor: pointer;
                    transition: all 0.15s;
                    text-align: left;
                }
                .setup-nav-link:hover {
                    background: var(--surface-elevated);
                    color: var(--text-primary);
                    border-color: var(--accent-warm-glow);
                }

                /* ── Buttons ── */
                .setup-btn {
                    display: flex;
                    align-items: center;
                    gap: 6px;
                    padding: 8px 16px;
                    border-radius: var(--radius-md);
                    font-size: 0.8rem;
                    font-weight: 600;
                    cursor: pointer;
                    transition: all 0.15s;
                    border: none;
                    white-space: nowrap;
                }
                .setup-btn:disabled {
                    opacity: 0.5;
                    cursor: not-allowed;
                }
                .setup-btn-primary {
                    background: var(--accent-warm);
                    color: #fff;
                }
                .setup-btn-primary:hover:not(:disabled) { opacity: 0.88; }
                .setup-btn-ghost {
                    background: var(--surface-tertiary);
                    color: var(--text-secondary);
                    border: 1px solid var(--border);
                }
                .setup-btn-ghost:hover:not(:disabled) {
                    background: var(--surface-elevated);
                    color: var(--text-primary);
                }
                .setup-btn-danger-ghost {
                    background: transparent;
                    color: var(--text-tertiary);
                    border: 1px solid var(--border);
                }
                .setup-btn-danger-ghost:hover {
                    background: rgba(239,68,68,0.08);
                    color: #ef4444;
                    border-color: rgba(239,68,68,0.3);
                }
                .setup-btn-danger {
                    background: #ef4444;
                    color: #fff;
                }
                .setup-btn-danger:hover:not(:disabled) { background: #dc2626; }

                /* ── Delete Modal ── */
                .setup-modal-overlay {
                    position: fixed;
                    inset: 0;
                    z-index: 300;
                    background: rgba(0,0,0,0.6);
                    backdrop-filter: blur(6px);
                    -webkit-backdrop-filter: blur(6px);
                    display: flex;
                    align-items: center;
                    justify-content: center;
                }
                .setup-modal {
                    width: 380px;
                    background: var(--surface-secondary);
                    border: 1px solid var(--border-strong);
                    border-radius: var(--radius-xl);
                    box-shadow: var(--shadow-xl);
                    padding: 28px 28px 24px;
                    display: flex;
                    flex-direction: column;
                    align-items: center;
                    text-align: center;
                    animation: setupModalIn 0.2s ease;
                }
                @keyframes setupModalIn {
                    from { opacity: 0; transform: scale(0.95) translateY(10px); }
                    to   { opacity: 1; transform: scale(1) translateY(0); }
                }
                .setup-modal-icon {
                    width: 52px;
                    height: 52px;
                    border-radius: 50%;
                    background: rgba(239,68,68,0.12);
                    color: #ef4444;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    margin-bottom: 16px;
                }
                .setup-modal-title {
                    font-size: 1.1rem;
                    font-weight: 700;
                    color: var(--text-primary);
                    margin: 0 0 10px;
                }
                .setup-modal-body {
                    font-size: 0.85rem;
                    color: var(--text-secondary);
                    line-height: 1.5;
                    margin: 0 0 24px;
                }
                .setup-modal-actions {
                    display: flex;
                    gap: 10px;
                    width: 100%;
                    justify-content: center;
                }
            `}</style>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { subscribeToSeries, subscribeToSeriesProjects } from '@/lib/firestore';
import { Project, Series } from '@/lib/types';
import { Card } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import {
    ChevronLeft,
    Book,
    Users,
    Settings as SettingsIcon,
    Plus,
    ExternalLink
} from 'lucide-react';
import Link from 'next/link';
import { toast } from 'sonner';
import { useAuth } from '@/lib/hooks/useAuth';

export default function SeriesDetailContent({ id }: { id: string }) {
    const router = useRouter();
    const [series, setSeries] = useState<Series | null>(null);
    const [projects, setProjects] = useState<Project[]>([]);
    const [loading, setLoading] = useState(true);
    const { user } = useAuth();

    useEffect(() => {
        if (!id) return;

        setLoading(true);
        const unsubscribeSeries = subscribeToSeries(
            id,
            (data) => {
                if (!data) {
                    toast.error('Series not found');
                    router.push('/series');
                    return;
                }
                setSeries(data);
                setLoading(false);
            },
            (err) => {
                console.error(err);
                toast.error('Failed to load series');
            }
        );

        const unsubscribeProjects = subscribeToSeriesProjects(
            id,
            (list) => setProjects(list),
            (err) => console.error(err)
        );

        return () => {
            unsubscribeSeries();
            unsubscribeProjects();
        };
    }, [id, router, user]);

    if (loading) {
        return (
            <div className="flex items-center justify-center p-20">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-accent-warm"></div>
            </div>
        );
    }

    return (
        <div className="series-detail-page">
            <header className="detail-header">
                <div className="header-left">
                    <Link href="/series" className="back-link">
                        <ChevronLeft size={20} />
                        <span>Back to Library</span>
                    </Link>
                    <div className="title-section">
                        <h1 className="series-title">{series?.title}</h1>
                        <p className="series-desc">{series?.description || 'No description provided.'}</p>
                    </div>
                </div>
                <div className="header-actions">
                    <Button variant="secondary">
                        <SettingsIcon size={18} />
                        <span>Series Settings</span>
                    </Button>
                </div>
            </header>

            <div className="detail-grid">
                {/* Left Column: Projects */}
                <section className="detail-section">
                    <div className="section-head">
                        <div className="head-title">
                            <Book size={20} className="head-icon" />
                            <h2>Project Library</h2>
                        </div>
                        <Button variant="ghost" size="sm">
                            <Plus size={16} />
                            <span>Add Project</span>
                        </Button>
                    </div>

                    <div className="projects-stack">
                        {projects.length === 0 ? (
                            <div className="empty-substate">
                                <p>No projects linked to this series yet.</p>
                            </div>
                        ) : (
                            projects.map((project) => (
                                <Card key={project.id} className="project-list-card">
                                    <div className="project-info">
                                        <h3 className="project-name">{project.title}</h3>
                                        <div className="project-stats">
                                            <span>{project.wordCount.toLocaleString()} words</span>
                                            <span className="dot"></span>
                                            <span>{project.chapterCount} chapters</span>
                                        </div>
                                    </div>
                                    <Link href={`/project/${project.id}`} className="view-link">
                                        <span>Open Book</span>
                                        <ExternalLink size={14} />
                                    </Link>
                                </Card>
                            ))
                        )}
                    </div>
                </section>

                {/* Right Column: Shared Entities */}
                <section className="detail-section">
                    <div className="section-head">
                        <div className="head-title">
                            <Users size={20} className="head-icon" />
                            <h2>Shared Codex</h2>
                        </div>
                        <Button variant="ghost" size="sm">
                            <Plus size={16} />
                            <span>Port Entity</span>
                        </Button>
                    </div>

                    <div className="entities-stack">
                        {(!series?.sharedEntityIds || series.sharedEntityIds.length === 0) ? (
                            <div className="empty-substate">
                                <p>No shared entities in this series.</p>
                                <p className="hint">Share characters or settings from a book's Codex to see them here.</p>
                            </div>
                        ) : (
                            <div className="entities-placeholder">
                                {series.sharedEntityIds.length} Entities Shared
                            </div>
                        )}
                    </div>
                </section>
            </div>

            <style jsx>{`
                .series-detail-page {
                    max-width: 1400px;
                    margin: 0 auto;
                    padding: 40px 24px;
                }
                .detail-header {
                    display: flex;
                    justify-content: space-between;
                    align-items: flex-start;
                    margin-bottom: 48px;
                }
                .back-link {
                    display: flex;
                    align-items: center;
                    gap: 4px;
                    color: var(--text-tertiary);
                    text-decoration: none;
                    font-size: 0.9rem;
                    font-weight: 600;
                    margin-bottom: 16px;
                    transition: color 0.2s;
                }
                .back-link:hover {
                    color: var(--accent-warm);
                }
                .series-title {
                    font-size: 2.25rem;
                    font-weight: 800;
