                }
                .project-stats {
                    display: flex;
                    align-items: center;
                    gap: 8px;
                    font-size: 0.8rem;
                    color: var(--text-tertiary);
                }
                .dot {
                    width: 3px;
                    height: 3px;
                    border-radius: 50%;
                    background: var(--border-strong);
                }
                .view-link {
                    display: flex;
                    align-items: center;
