import { useState, useEffect, useRef, useCallback } from 'react';
import { updateChapter, updateProjectWordCountDelta, saveVersion } from '@/lib/firestore';
import { saveChapterOffline, isOnline, setupAutoSync, syncOfflineChanges } from '@/lib/offline-storage';
import type { SyncStatus } from '@/lib/types';
import { useAuth } from '@/lib/hooks/useAuth';
import { toast } from 'sonner';

const MAX_RETRIES = 3;
const SAVE_DELAY = 2000;

export function useAutoSave(
    chapterId: string | null,
    projectId: string | null,
    content: string,
    disabled = false,
) {
    const { user } = useAuth();
    const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');
    const [lastSaved, setLastSaved] = useState<Date | null>(null);
    const [isOffline, setIsOffline] = useState(false);
    const retryCount = useRef(0);
    const contentRef = useRef(content);
    const lastVersionTime = useRef<number>(Date.now());
    const prevWordCountRef = useRef<number>(0);

    // Keep ref in sync
    contentRef.current = content;

    // Monitor online/offline status
    useEffect(() => {
        const handleOnline = () => {
            setIsOffline(false);
            toast.success('Connection restored. Syncing offline changes...');
        };
        const handleOffline = () => {
            setIsOffline(true);
            toast.warning('You are offline. Changes will be saved locally.');
        };

        window.addEventListener('online', handleOnline);
        window.addEventListener('offline', handleOffline);

        // Initial check
        setIsOffline(!isOnline());

        return () => {
            window.removeEventListener('online', handleOnline);
            window.removeEventListener('offline', handleOffline);
        };
    }, []);

    // Setup auto-sync when connection restores
    useEffect(() => {
        const cleanup = setupAutoSync((result) => {
            if (result.success > 0) {
                toast.success(`Synced ${result.success} offline change(s)`);
            }
            if (result.failed > 0) {
                toast.error(`Failed to sync ${result.failed} change(s)`);
            }
        });

        return cleanup;
    }, []);

    const save = useCallback(async () => {
        if (!chapterId || !projectId || disabled) return;

        setSyncStatus('saving');

        try {
            // Calculate word count for offline storage
            const wordCount = contentRef.current
                ? contentRef.current.replace(/<[^>]*>/g, '').trim().split(/\s+/).length
                : 0;

            // Try to save to Firestore first
            if (isOnline()) {
                // Compute word count delta and update incrementally (avoids full chapter scan)
                const newWordCount = wordCount;
                const delta = newWordCount - prevWordCountRef.current;
                prevWordCountRef.current = newWordCount;

                await updateChapter(chapterId, { content: contentRef.current, wordCount: newWordCount });
                await updateProjectWordCountDelta(projectId, delta);

                // Check version threshold: 60 seconds (PRD US-004-01)
                const now = Date.now();
                if (user && now - lastVersionTime.current > 60 * 1000) {
                    await saveVersion(chapterId, user.uid, contentRef.current, 'autosave');
                    lastVersionTime.current = now;
                }

                setSyncStatus('saved');
                setLastSaved(new Date());
                retryCount.current = 0;
            } else {
                // Offline: save to IndexedDB
                await saveChapterOffline(
                    chapterId,
                    projectId,
                    contentRef.current,
                    { content: contentRef.current }, // contentJSON
                    wordCount
                );

                setSyncStatus('offline');
                setLastSaved(new Date());
                retryCount.current = 0;
            }
        } catch (err) {
            console.error('Auto-save failed:', err);
            retryCount.current += 1;

            // If Firestore fails, try IndexedDB as fallback
            if (retryCount.current === 1) {
                try {
                    const wordCount = contentRef.current
                        ? contentRef.current.replace(/<[^>]*>/g, '').trim().split(/\s+/).length
                        : 0;

                    await saveChapterOffline(
                        chapterId,
                        projectId,
                        contentRef.current,
                        { content: contentRef.current },
                        wordCount
                    );

                    setSyncStatus('offline');
                    setLastSaved(new Date());
                    toast.info('Saved locally. Will sync when online.');
                    retryCount.current = 0;
                    return;
                } catch (offlineErr) {
                    console.error('Offline save also failed:', offlineErr);
                }
            }

            if (retryCount.current < MAX_RETRIES) {
                // Retry after a short delay
                setTimeout(save, 1000 * retryCount.current);
            } else {
                setSyncStatus('error');
                retryCount.current = 0;
                toast.error('Failed to save changes. Please check your connection.');
            }
        }
    }, [chapterId, projectId, user, disabled]);

    useEffect(() => {
        if (!chapterId || !content) return;

        setSyncStatus('idle');
        const timeoutId = setTimeout(save, SAVE_DELAY);
        return () => clearTimeout(timeoutId);
    }, [chapterId, content, save]);

    return { syncStatus, lastSaved, isOffline };
}

'use client';

import { useState, useCallback, useRef, useEffect } from 'react';
import { useAuth } from './useAuth';
import { getProject, getChapters, getEntities } from '@/lib/local-db';

export interface ChatMessage {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: number;
}

export interface ChatConfig {
  projectId?: string;
  personaId?: string;
  systemPrompt?: string;
  provider?: string;
  model?: string;
}

const CHAT_HISTORY_KEY = (projectId: string) =>
  `novello_chat_${projectId}_unified`;

export function useChat(config: ChatConfig = {}) {
  const { projectId, personaId, systemPrompt: customPrompt, provider, model } = config;
  const { user } = useAuth();
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isStreaming, setIsStreaming] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const abortRef = useRef<AbortController | null>(null);

  // Load chat history from localStorage on mount
  useEffect(() => {
    if (!projectId) return;
    try {
      const stored = localStorage.getItem(CHAT_HISTORY_KEY(projectId));
      if (stored) {
        setMessages(JSON.parse(stored));
      }
    } catch { /* ignore parse errors */ }
  }, [projectId]);

  // Persist messages to localStorage whenever they update
  useEffect(() => {
    if (!projectId || messages.length === 0) return;
    try {
      // Keep last 50 messages to avoid storage bloat
      const toStore = messages.slice(-50);
      localStorage.setItem(CHAT_HISTORY_KEY(projectId), JSON.stringify(toStore));
    } catch { /* ignore storage errors */ }
  }, [messages, projectId]);

  const sendMessage = useCallback(
    async (content: string, context?: { projectTitle?: string; chapterContent?: string; overrideSystemPrompt?: string }) => {
      if (!content.trim() || isStreaming) return;

      const userMsg: ChatMessage = {
        id: `user-${Date.now()}`,
        role: 'user',
        content: content.trim(),
        timestamp: Date.now(),
      };

      setMessages((prev) => [...prev, userMsg]);
      setIsStreaming(true);
      setError(null);

      const assistantId = `assistant-${Date.now()}`;
      const assistantMsg: ChatMessage = {
        id: assistantId,
        role: 'assistant',
        content: '',
        timestamp: Date.now(),
      };
      setMessages((prev) => [...prev, assistantMsg]);

      const controller = new AbortController();
      abortRef.current = controller;

      try {
        let systemPrompt = context?.overrideSystemPrompt || customPrompt ||
          'You are Novello AI, a creative writing assistant. Be helpful, concise, and inspiring. Help the writer with their creative process.';
        if (context?.projectTitle) {
          systemPrompt += `\n\nThe writer is currently working on a project titled "${context.projectTitle}".`;
        }
        if (context?.chapterContent) {
          systemPrompt += `\n\nHere is some of their recent writing for context:\n${context.chapterContent.slice(0, 2000)}`;
        }

        let aiProvider = provider || 'ollama';
        if (!provider && typeof window !== 'undefined') {
          const saved = localStorage.getItem('novello-settings');
          if (saved) {
            try {
              const parsed = JSON.parse(saved);
              aiProvider = parsed.provider || aiProvider;
            } catch { /* ignore */ }
          }
        }

        let projectData, chaptersData, entitiesData;
        if (projectId) {
          projectData = await getProject(projectId);
          chaptersData = await getChapters(projectId);
          entitiesData = await getEntities(projectId);
        }

        const res = await fetch('/api/ai/generate', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${user?.uid ?? 'local'}`,
          },
          body: JSON.stringify({
            prompt: `${systemPrompt}\n\nUser: ${content.trim()}`,
            provider: aiProvider,
            model,
            mode: 'stream',
            projectId,
            projectData,
            chaptersData,
            entitiesData,
          }),
          signal: controller.signal,
        });

        if (!res.ok) {
          const data = await res.json();
          throw new Error(data.error || 'AI response failed');
        }

        const reader = res.body?.getReader();
        if (!reader) throw new Error('No response stream');

        const decoder = new TextDecoder();
        let accumulated = '';
        let buffer = '';

        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split('\n');
          buffer = lines.pop() || '';

          for (const line of lines) {
            if (line.startsWith('0:')) {
              try {
                const text = JSON.parse(line.substring(2));
                accumulated += text;
                setMessages((prev) =>
                  prev.map((m) =>
                    m.id === assistantId ? { ...m, content: accumulated } : m
                  )
                );
              } catch { /* skip invalid */ }
            }
          }
        }
      } catch (err) {
        if ((err as Error).name === 'AbortError') {
          // cancelled by user
        } else {
          const msg = err instanceof Error ? err.message : 'Chat failed';
          setError(msg);
          setMessages((prev) =>
            prev.map((m) =>
              m.id === assistantId
                ? { ...m, content: 'Sorry, I encountered an error. Please try again.' }
                : m
            )
          );
        }
      } finally {
        setIsStreaming(false);
        abortRef.current = null;
      }
    },
    [isStreaming, user, projectId, personaId, customPrompt, provider, model]
  );

  const cancelStream = useCallback(() => {
    abortRef.current?.abort();
    setIsStreaming(false);
  }, []);

  const clearMessages = useCallback(() => {
    setMessages([]);
    setError(null);
    if (projectId) {
      localStorage.removeItem(CHAT_HISTORY_KEY(projectId));
    }
  }, [projectId]);

  return { messages, isStreaming, error, sendMessage, cancelStream, clearMessages };
}

'use client';

import { useState, useCallback, useMemo } from 'react';
import { Chapter, Project } from '@/lib/types';
import { updateChapter, updateProject } from '@/lib/firestore';
import { useAuth } from './useAuth';


// =============================================
// useContextEngine — Rolling Context from Chapter Summaries
// =============================================

export function useContextEngine(chapters: Chapter[]) {
    const { user } = useAuth();
    const [summarizing, setSummarizing] = useState(false);

    // Build rolling context from last 3 chapters' summaries
    const rollingContext = useMemo(() => {
        const sorted = [...chapters].sort((a, b) => a.order - b.order);
        const last3 = sorted.slice(-3);
        const summaries = last3
            .map((ch) => ch.lastSummary)
            .filter(Boolean);
        if (summaries.length === 0) return '';
        return `[Rolling Story Context — Last ${summaries.length} Chapter(s)]\n${summaries.join('\n---\n')}`;
    }, [chapters]);

    // Summarize a specific chapter and save the summary
    const summarizeChapter = useCallback(
        async (chapter: Chapter, provider: string = 'ollama', model: string = '') => {
            if (!chapter.content || chapter.content.trim().length < 50) return;

            setSummarizing(true);
            try {
                // Strip HTML tags for a cleaner prompt
                const textContent = chapter.content.replace(/<[^>]+>/g, '').trim();

                const token = user?.uid ?? 'local';
                const res = await fetch('/api/ai/generate', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                        'Authorization': `Bearer ${token}`
                    },
                    body: JSON.stringify({
                        prompt: textContent,
                        provider,
                        model,
                        mode: 'json',
                        action: 'summarize',
                        projectId: chapter.projectId,
                    }),
                });

                if (!res.ok) throw new Error('Summarization failed');

                const data = await res.json();
                const summary = data.result?.trim() || '';

                // Save summary to Firestore
                await updateChapter(chapter.id, { lastSummary: summary });
            } catch (err) {
                console.error('[Context Engine] Summarization failed:', err);
            } finally {
                setSummarizing(false);
            }
        },
        [user]
    );

    // Sync all summaries to project.contextRollup
    const syncContextRollup = useCallback(async () => {
        if (!chapters.length) return;
        const projectId = chapters[0].projectId;

        // Collect summaries
        const summaries = chapters
            .filter((ch) => ch.lastSummary && ch.lastSummary.length > 0)
            .sort((a, b) => a.order - b.order)
            .map((ch) => ({
                chapterId: ch.id,
                order: ch.order,
                title: ch.title,
                summary: ch.lastSummary,
            }));

        if (summaries.length === 0) return;

        try {
            await updateProject(projectId, {
                contextRollup: {
                    chapterSummaries: summaries,
                    lastUpdated: Date.now(),
                },
            });
        } catch (err) {
            console.error('[Context Engine] Failed to sync rollup:', err);
        }
    }, [chapters]);

    // Summarize all chapters that lack summaries — runs up to 3 in parallel
    const summarizeAll = useCallback(
        async (provider: string = 'ollama', model: string = '') => {
            const needsSummary = chapters.filter(
                (ch) => ch.content && ch.content.trim().length >= 50 && !ch.lastSummary
            );
            const CONCURRENCY = 3;
            for (let i = 0; i < needsSummary.length; i += CONCURRENCY) {
                const batch = needsSummary.slice(i, i + CONCURRENCY);
                await Promise.allSettled(
                    batch.map((ch) => summarizeChapter(ch, provider, model))
                );
            }
        },
        [chapters, summarizeChapter]
    );

    return {
        rollingContext,
        summarizing,
        summarizeChapter,
        syncContextRollup,
        summarizeAll,
        hasSummaries: chapters.some((ch) => ch.lastSummary),
    };
}

import { useState, useCallback } from 'react';
import { useChapters } from './useChapters';
import { useEntities } from './useEntities';
import { useAuth } from './useAuth';
import { ContinuityAlert, Chapter } from '../types';


export function useContinuityChecker(projectId: string) {
    const { chapters } = useChapters(projectId);
    const { entities } = useEntities(projectId);
    const { user } = useAuth();
    const [alerts, setAlerts] = useState<ContinuityAlert[]>([]);
    const [checking, setChecking] = useState(false);

    const checkContinuity = useCallback(async (chapterContent: string, currentChapterId: string) => {
        if (!user) return;

        setChecking(true);
        try {
            // Build context from previous chapters
            // Find current chapter order
            const currentChapter = chapters.find(ch => ch.id === currentChapterId);
            const currentOrder = currentChapter ? currentChapter.order : 0;

            const previousChapters = chapters
                .filter(c => c.order < currentOrder)
                .sort((a, b) => a.order - b.order);

            const contextText = previousChapters.map(c => `Chapter: ${c.title}\nSynopsis: ${c.synopsis || c.lastSummary || 'No summary available.'}`).join('\n\n');

            const entitiesText = entities.map(e => `Name: ${e.name} (${e.type})\nDescription: ${e.description}\nAppearance: ${e.appearance}`).join('\n\n');

            const res = await fetch('/api/ai/continuity', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    chapterContent,
                    entities: entitiesText,
                    previousContext: contextText || 'Start of story.',
                })
            });

            if (!res.ok) throw new Error('Failed to check continuity');

            const data = await res.json();

            if (data.alerts && Array.isArray(data.alerts)) {
                const newAlerts: ContinuityAlert[] = data.alerts.map((a: any) => ({
                    id: crypto.randomUUID(),
                    projectId,
                    userId: user.uid,
                    chapterId: currentChapterId,
                    entityId: null, // AI doesn't return ID, logic could be improved to match by name
                    type: a.type || 'contradiction',
                    severity: a.severity || 'warning',
                    message: a.message,
                    sourceChapterId: currentChapterId, // The alert is ABOUT this chapter
                    sourceExcerpt: '', // Could be filled if we knew previous source
                    flaggedExcerpt: a.quote || '',
                    status: 'open',
                  createdAt: Date.now(),
                }));
                setAlerts(newAlerts);
            } else {
                setAlerts([]);
            }
        } catch (error) {
            console.error('Continuity check failed:', error);
            // toast.error('Check failed'); // Optional
        } finally {
            setChecking(false);
        }
    }, [chapters, entities, projectId, user]);

    const dismissAlert = useCallback((alertId: string) => {
        setAlerts(prev => prev.filter(a => a.id !== alertId));
    }, []);

    return { checkContinuity, alerts, checking, dismissAlert };
}

'use client';

import { useState, useCallback } from 'react';
import { useAuth } from '@/lib/hooks/useAuth';
import { getProject, getChapters } from '@/lib/local-db';

export interface PublishMetadata {
    author: string;
    description: string;
    isbn: string;
    categories: string;
    coverUrl: string | null;
}

export function usePublish() {
    const { user } = useAuth();
    const [metadata, setMetadata] = useState<PublishMetadata>({
        author: '',
        description: '',
        isbn: '',
        categories: '',
        coverUrl: null,
    });
    const [exporting, setExporting] = useState(false);
    const [exportError, setExportError] = useState<string | null>(null);

    const updateMetadata = useCallback((updates: Partial<PublishMetadata>) => {
        setMetadata((prev) => ({ ...prev, ...updates }));
    }, []);

    const exportEpub = useCallback(
        async (projectId: string, projectTitle?: string) => {
            setExporting(true);
            setExportError(null);
            try {
                // Fetch project + chapters from local IndexedDB on the client
                const [project, chapters] = await Promise.all([
                    getProject(projectId),
                    getChapters(projectId),
                ]);

                if (!project) throw new Error('Project not found in local database');
                if (!chapters || chapters.length === 0) throw new Error('No chapters found to export');

                const token = user?.uid ?? 'local';
                const res = await fetch('/api/export/epub', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                        'Authorization': `Bearer ${token}`,
                    },
                    // Send the data the server needs — no Firestore reads required
                    body: JSON.stringify({ project, chapters }),
                });
                if (!res.ok) {
                    const data = await res.json();
                    throw new Error(data.error || 'Export failed');
                }
                const blob = await res.blob();
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                const safeName = (projectTitle || project.title || 'manuscript').replace(/[^a-zA-Z0-9\s\-_]/g, '').trim() || 'manuscript';
                a.download = `${safeName}.epub`;
                a.click();
                URL.revokeObjectURL(url);
            } catch (err) {
                setExportError(err instanceof Error ? err.message : 'Export failed');
            } finally {
                setExporting(false);
            }
        },
        [user]
    );

    const exportPdf = useCallback(
        async (projectId: string, projectTitle?: string) => {
            setExporting(true);
            setExportError(null);
            try {
                // Fetch project + chapters from local IndexedDB on the client
                const [project, chapters] = await Promise.all([
                    getProject(projectId),
                    getChapters(projectId),
                ]);

                if (!project) throw new Error('Project not found in local database');
                if (!chapters || chapters.length === 0) throw new Error('No chapters found to export');

                const sorted = [...chapters].sort((a, b) => (a.order || 0) - (b.order || 0));

                const html = `
                <div style="font-family: 'Georgia', serif; font-size: 12pt; line-height: 1.6; color: #1a1a1a; max-width: 6.5in; margin: 0 auto; padding: 1in;">
                    <div style="text-align: center; padding-top: 3in; page-break-after: always;" class="page-break">
                        <h1 style="font-size: 28pt; font-weight: bold; margin-bottom: 0.5in;">${project.title || 'Untitled'}</h1>
                        <div style="font-size: 16pt; color: #555;">by ${project.metadata?.authorName || 'Author'}</div>
                    </div>
                    ${sorted.map(ch => `
                        <div style="page-break-before: always;" class="page-break">
                            <h2 style="font-size: 18pt; font-weight: bold; margin-bottom: 0.3in; text-align: center;">${ch.title}</h2>
                            <div style="text-indent: 0.5in;">${ch.content || '<p>(Empty chapter)</p>'}</div>
                        </div>
                    `).join('')}
                </div>`;

                const safeName = (projectTitle || project.title || 'manuscript').replace(/[^a-zA-Z0-9\s\-_]/g, '').trim() || 'manuscript';

                // Dynamically import html2pdf to prevent SSR issues
                // @ts-ignore
                const html2pdf = (await import('html2pdf.js')).default;

                const opt = {
                    margin:       [0.5, 0.5] as [number, number], // margin in inches
                    filename:     `${safeName}.pdf`,
                    image:        { type: 'jpeg' as const, quality: 0.98 },
                    html2canvas:  { scale: 2 },
                    pagebreak:    { mode: 'css', before: '.page-break' },
                    jsPDF:        { unit: 'in', format: 'letter', orientation: 'portrait' as const }
                };

                const element = document.createElement('div');
                element.innerHTML = html;

                await html2pdf().set(opt).from(element).save();
            } catch (err) {
                setExportError(err instanceof Error ? err.message : 'PDF export failed');
            } finally {
                setExporting(false);
            }
        },
        [user]
    );

    return {
        metadata,
        updateMetadata,
        exporting,
        exportError,
        exportEpub,
        exportPdf,
    };
}

