export type Theme = 'play' | 'global' | 'futuro';

export interface ThemeMeta {
    id: Theme;
    name: string;
    label: string;
    description: string;
    icon: string;
    colorScheme: 'dark' | 'light' | 'dim';
    swatches: [string, string, string];
    colors: {
        primary: string;
