const VALID_THEMES = new Set<string>(Object.keys(THEME_META));
const THEME_IDS = Object.keys(THEME_META) as Theme[];

interface ThemeContextValue {
    theme: Theme;
    toggleTheme: () => void;
    setTheme: (t: Theme) => void;
    themeMeta: ThemeMeta;
}

function getThemeMeta(t: Theme): ThemeMeta {
    return THEME_META[t] || THEME_META['play'];
}

const ThemeContext = createContext<ThemeContextValue>({
    theme: 'play',
    toggleTheme: () => { },
    setTheme: () => { },
    themeMeta: THEME_META['play'],
});

export function ThemeProvider({ children }: { children: ReactNode }) {
    const [theme, setThemeState] = useState<Theme>('play');

    useEffect(() => {
        const stored = localStorage.getItem('novello-theme');
        const initial: Theme = (stored && VALID_THEMES.has(stored)) ? (stored as Theme) : 'play';
        setThemeState(initial);
        const meta = getThemeMeta(initial);
        document.documentElement.setAttribute('data-theme', initial);
        document.documentElement.style.colorScheme = meta.colorScheme;
    }, []);

    const applyTheme = useCallback((t: Theme) => {
        setThemeState(t);
        const meta = getThemeMeta(t);
        document.documentElement.setAttribute('data-theme', t);
        document.documentElement.style.colorScheme = meta.colorScheme;
        localStorage.setItem('novello-theme', t);
    }, []);

    const toggleTheme = useCallback(() => {
        const idx = THEME_IDS.indexOf(theme);
        const next = THEME_IDS[(idx + 1) % THEME_IDS.length];
        applyTheme(next);
    }, [theme, applyTheme]);

    const setTheme = useCallback((t: Theme) => {
        applyTheme(t);
    }, [applyTheme]);

    const themeMeta = getThemeMeta(theme);

    return (
        <ThemeContext.Provider value={{ theme, toggleTheme, setTheme, themeMeta }}>
            {children}
        </ThemeContext.Provider>
    );
}

export function useTheme() {
    return useContext(ThemeContext);
}

'use client';

import { useState, useCallback, useRef, useEffect } from 'react';
import { piperService } from '@/lib/piper-service';

/**
 * Voice interaction hook providing:
 * - Speech-to-Text (STT) via Web Speech API (SpeechRecognition)
 * - Text-to-Speech (TTS) via Piper service (with browser fallback)
 */

interface VoiceState {
    isListening: boolean;
    isSpeaking: boolean;
    transcript: string;
    interimTranscript: string;
    isSupported: boolean;
    error: string | null;
}

interface SpeechRecognitionEvent {
    resultIndex: number;
    results: SpeechRecognitionResultList;
}

interface SpeechRecognitionErrorEvent {
    error: string;
}

export function useVoiceInteraction() {
    const [state, setState] = useState<VoiceState>({
        isListening: false,
        isSpeaking: false,
        transcript: '',
        interimTranscript: '',
        isSupported: false,
        error: null,
    });

    const recognitionRef = useRef<any>(null);
    const audioRef = useRef<HTMLAudioElement | null>(null);

    // Check browser support
    useEffect(() => {
        const SpeechRecognition =
            (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
        setState((prev) => ({ ...prev, isSupported: !!SpeechRecognition }));
    }, []);

    /**
     * Start listening for voice input via the Web Speech API.
     * Returns a promise that resolves with the final transcript.
     */
    const startListening = useCallback((): Promise<string> => {
        return new Promise((resolve, reject) => {
            const SpeechRecognition =
                (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

            if (!SpeechRecognition) {
                const err = 'Speech recognition not supported in this browser.';
                setState((prev) => ({ ...prev, error: err }));
                reject(new Error(err));
                return;
            }

            const recognition = new SpeechRecognition();
            recognition.continuous = false;
            recognition.interimResults = true;
            recognition.lang = 'en-US';
            recognition.maxAlternatives = 1;

            recognitionRef.current = recognition;

            let finalTranscript = '';

            recognition.onstart = () => {
                setState((prev) => ({
                    ...prev,
                    isListening: true,
                    transcript: '',
                    interimTranscript: '',
                    error: null,
                }));
            };

            recognition.onresult = (event: SpeechRecognitionEvent) => {
                let interim = '';
                for (let i = event.resultIndex; i < event.results.length; i++) {
                    const result = event.results[i];
                    if (result.isFinal) {
                        finalTranscript += result[0].transcript;
                    } else {
                        interim += result[0].transcript;
                    }
                }
                setState((prev) => ({
                    ...prev,
                    transcript: finalTranscript,
                    interimTranscript: interim,
                }));
            };

            recognition.onend = () => {
                setState((prev) => ({
                    ...prev,
                    isListening: false,
                    interimTranscript: '',
                }));
                resolve(finalTranscript.trim());
            };

            recognition.onerror = (event: SpeechRecognitionErrorEvent) => {
                const errMsg = `Speech recognition error: ${event.error}`;
                setState((prev) => ({
                    ...prev,
                    isListening: false,
                    error: errMsg,
                }));
                reject(new Error(errMsg));
            };

            recognition.start();
        });
    }, []);

    /**
     * Stop listening for voice input.
     */
    const stopListening = useCallback(() => {
        if (recognitionRef.current) {
            recognitionRef.current.stop();
            recognitionRef.current = null;
        }
        setState((prev) => ({ ...prev, isListening: false }));
    }, []);

    /**
     * Speak text aloud using Piper TTS (or browser SpeechSynthesis fallback).
     */
    const speakText = useCallback(async (text: string, voiceId?: string) => {
        if (!text.trim()) return;

        setState((prev) => ({ ...prev, isSpeaking: true }));

        try {
            // Try Piper neural TTS first
            await piperService.init();
            if (piperService.isNeuralAvailable()) {
                const audio = await piperService.speak(text, voiceId || 'piper-lessac');
                if (audio) {
                    audioRef.current = audio;
                    audio.onended = () => {
                        setState((prev) => ({ ...prev, isSpeaking: false }));
                    };
                    return;
                }
            }

            // Fallback to browser SpeechSynthesis
            const utterance = new SpeechSynthesisUtterance(text);
            utterance.rate = 0.95;
            utterance.pitch = 1.0;

            // Try to find a good English voice
            const voices = window.speechSynthesis.getVoices();
            const premiumVoice = voices.find(
                (v) =>
                    v.name.includes('Premium') ||
                    v.name.includes('Samantha') ||
                    v.name.includes('Google')
            ) || voices.find((v) => v.lang.startsWith('en')) || voices[0];

            if (premiumVoice) utterance.voice = premiumVoice;

            utterance.onend = () => {
                setState((prev) => ({ ...prev, isSpeaking: false }));
            };
            utterance.onerror = () => {
                setState((prev) => ({ ...prev, isSpeaking: false }));
            };

            window.speechSynthesis.speak(utterance);
        } catch (err) {
            console.error('TTS error:', err);
            setState((prev) => ({ ...prev, isSpeaking: false }));
        }
    }, []);

    /**
     * Stop any ongoing speech output.
     */
    const stopSpeaking = useCallback(() => {
        if (audioRef.current) {
            audioRef.current.pause();
            audioRef.current = null;
        }
        if (typeof window !== 'undefined') {
            window.speechSynthesis.cancel();
        }
        setState((prev) => ({ ...prev, isSpeaking: false }));
    }, []);

    return {
        ...state,
        startListening,
        stopListening,
        speakText,
        stopSpeaking,
    };
}

import mammoth from 'mammoth';

export interface ParsedChapter {
    title: string;
    content: string;
}

export interface ParsedManuscript {
    title: string;
    chapters: ParsedChapter[];
    fullText: string;
}

/**
 * Parses a manuscript file (.docx, .txt, .md) into text and chapters.
 */
export async function parseManuscript(file: File): Promise<ParsedManuscript> {
    let fullText = '';
    const fileType = file.name.split('.').pop()?.toLowerCase();

    try {
        if (fileType === 'docx') {
            const arrayBuffer = await file.arrayBuffer();
            // @ts-ignore: mammoth might lack types in this environment
            const result = await mammoth.extractRawText({ arrayBuffer });
            fullText = result.value;
        } else if (fileType === 'txt' || fileType === 'md') {
            fullText = await file.text();
        } else {
            throw new Error(`Unsupported file type: .${fileType}`);
        }
    } catch (error) {
        console.error('Error reading file:', error);
        throw new Error('Failed to read file content.');
    }

    // Basic Chapter Parsing Logic
    // Looks for lines starting with "Chapter", "Part", "Prologue", "Epilogue" followed by optional number
    const chapterRegex = /(?:^|\n)\s*(Chapter|Part|Prologue|Epilogue)\s*(\d+|One|Two|Three|I|II|III)?.*(?:\r?\n|$)/gi;

    // If no chapters found, treat whole text as one chapter
    // We can also split by double newlines if no headers found? No, that's too aggressive.

    const chapters: ParsedChapter[] = [];

    // Reset regex state
    chapterRegex.lastIndex = 0;

    // Find all matches
    const matches = Array.from(fullText.matchAll(chapterRegex));

    if (matches.length === 0) {
        // No chapters detected, return whole text as one chapter
        chapters.push({
            title: file.name.replace(/\.[^/.]+$/, ""),
            content: fullText.trim()
        });
    } else {
        for (let i = 0; i < matches.length; i++) {
            const currentMatch = matches[i];
            const nextMatch = matches[i + 1];

            const startIndex = currentMatch.index! + currentMatch[0].length;
            const endIndex = nextMatch ? nextMatch.index! : fullText.length;

            const title = currentMatch[0].trim();
            const content = fullText.slice(startIndex, endIndex).trim();

            if (content.length > 0) {
                chapters.push({ title, content });
            }
        }

        // Handle prologue text if it exists before the first chapter?
        if (matches[0].index! > 0) {
            const prologueContent = fullText.slice(0, matches[0].index!).trim();
            if (prologueContent.length > 0) {
                chapters.unshift({
                    title: 'Front Matter',
                    content: prologueContent
                });
            }
        }
    }

    return {
        title: file.name.replace(/\.[^/.]+$/, ""),
        fullText,
        chapters
    };
}

import { openDB, IDBPDatabase } from 'idb';
import { Project, Chapter, Entity, Series, VoiceClone, WritingSession, ChapterCritique } from './types';

const DB_NAME = 'novello-ai-local';


interface NovelloSchema {
  projects: {
    key: string;
    value: Project;
    indexes: { 'by-updated': number };
  };
  chapters: {
    key: string;
    value: Chapter;
    indexes: { 'by-project': string; 'by-order': number };
  };
  entities: {
    key: string;
    value: Entity;
    indexes: { 'by-project': string; 'by-type': string };
  };
  series: {
    key: string;
    value: Series;
    indexes: { 'by-updated': number };
  };
  clones: {
    key: string;
    value: VoiceClone;
    indexes: { 'by-user': string; 'by-status': string };
  };
  versions: {
    key: string;
    value: import('./types').ChapterVersion;
    indexes: { 'by-chapter': string };
  };
  writing_sessions: {
    key: string;
    value: WritingSession;
    indexes: { 'by-project': string; 'by-date': string };
  };
  chapter_critiques: {
    key: string;
    value: ChapterCritique;
    indexes: { 'by-chapter': string };
  };
}

let dbPromise: Promise<IDBPDatabase<NovelloSchema>> | null = null;

export const getDB = () => {
  if (!dbPromise) {
    dbPromise = openDB<NovelloSchema>(DB_NAME, 3, {
      upgrade(db, oldVersion) {
        // Version 1 — core stores
        if (oldVersion < 1) {
          const projectStore = db.createObjectStore('projects', { keyPath: 'id' });
          projectStore.createIndex('by-updated', 'updatedAt');

          const chapterStore = db.createObjectStore('chapters', { keyPath: 'id' });
          chapterStore.createIndex('by-project', 'projectId');
          chapterStore.createIndex('by-order', 'order');

          const entityStore = db.createObjectStore('entities', { keyPath: 'id' });
          entityStore.createIndex('by-project', 'projectId');
          entityStore.createIndex('by-type', 'type');

          const seriesStore = db.createObjectStore('series', { keyPath: 'id' });
          seriesStore.createIndex('by-updated', 'updatedAt');
        }
        // Version 2 — voice clones store
        if (oldVersion < 2) {
          const clonesStore = db.createObjectStore('clones', { keyPath: 'id' });
          clonesStore.createIndex('by-user', 'userId');
          clonesStore.createIndex('by-status', 'status');
        }
        // Version 3 — version history store
        if (oldVersion < 3) {
          const versionsStore = db.createObjectStore('versions', { keyPath: 'id' });
          versionsStore.createIndex('by-chapter', 'chapterId');
        }
        // Version 4 — writing sessions + chapter critiques
        if (oldVersion < 4) {
          const sessionsStore = db.createObjectStore('writing_sessions', { keyPath: 'id' });
          sessionsStore.createIndex('by-project', 'projectId');
          sessionsStore.createIndex('by-date', 'date');

          const critiquesStore = db.createObjectStore('chapter_critiques', { keyPath: 'id' });
          critiquesStore.createIndex('by-chapter', 'chapterId');
        }
      },
    });
  }
  return dbPromise;
};

/* ─── Project Operations ─────────────────────────────────────── */
export async function saveProject(project: Project) {
  const db = await getDB();
  await db.put('projects', {
    ...project,
    updatedAt: Date.now(),
  });
}

export async function getProject(id: string) {
  const db = await getDB();
  return db.get('projects', id);
}

export async function getAllProjects() {
  const db = await getDB();
  return db.getAllFromIndex('projects', 'by-updated');
}

export async function deleteProject(id: string) {
  const db = await getDB();
  const tx = db.transaction(['projects', 'chapters', 'entities'], 'readwrite');

  // Delete project
  await tx.objectStore('projects').delete(id);

  // Delete associated chapters (cascade)
  const chapters = await tx.objectStore('chapters').index('by-project').getAllKeys(id);
  for (const cId of chapters) {
    await tx.objectStore('chapters').delete(cId);
  }

  // Delete associated entities
  const entities = await tx.objectStore('entities').index('by-project').getAllKeys(id);
  for (const eId of entities) {
    await tx.objectStore('entities').delete(eId);
  }

  await tx.done;
}

