import { POST as AudioBookPOST } from '../../src/app/api/ai/audiobook/route';
import { POST as AudioBookCancelPOST } from '../../src/app/api/ai/audiobook/cancel/route';
import { POST as VoicePreviewPOST } from '../../src/app/api/ai/voices/preview/route';

function createRequest(body: any) {
    return new NextRequest('http://localhost:3000/api/mock', {
        method: 'POST',
        headers: {
            'Authorization': 'Bearer mock-token',
            'Content-Type': 'application/json'
        },
        body: JSON.stringify(body)
    });
}

describe('API Contract Validations (Strict Zod Schemas)', () => {

    describe('POST /api/ai/audiobook', () => {
        it('should accept valid payload', async () => {
            const req = createRequest({
                projectId: 'prod-123',
                settings: {
                    voiceId: 'voice-1',
                    speed: 1.5
                }
            });
            const res = await AudioBookPOST(req);
            // Even if queue fails internally in mock, we just want to ensure it didn't return 400 Bad Request
            expect(res.status).not.toBe(400);
        });

        it('should reject missing required fields', async () => {
            const req = createRequest({
                settings: { voiceId: 'voice-1' } // Missing projectId
            });
            const res = await AudioBookPOST(req);
            expect(res.status).toBe(400);
            const data = await res.json();
            expect(data.error).toBe('Invalid request payload');
        });

        it('should reject unknown keys (strict)', async () => {
            const req = createRequest({
                projectId: 'prod-123',
                settings: {
                    voiceId: 'voice-1'
                },
                maliciousKey: 'drop_tables' // Unknown key
            });
            const res = await AudioBookPOST(req);
            expect(res.status).toBe(400);
            const data = await res.json();
            expect(data.error).toBe('Invalid request payload');
        });
    });

    describe('POST /api/ai/audiobook/cancel', () => {
        it('should accept valid payload', async () => {
            const req = createRequest({ exportId: 'export-123' });
            const res = await AudioBookCancelPOST(req);
            expect(res.status).not.toBe(400);
        });

        it('should reject unknown keys (strict)', async () => {
            const req = createRequest({
                exportId: 'export-123',
                hackThePlanet: true
            });
            const res = await AudioBookCancelPOST(req);
            expect(res.status).toBe(400);
        });
    });

    describe('POST /api/ai/voices/preview', () => {
        it('should accept valid payload', async () => {
            const req = createRequest({
                text: 'Hello world',
                engineVoiceId: 'en_US-lessac-high'
            });
            const res = await VoicePreviewPOST(req);
            // It might fail 500 locally because of missing Piper/Storage mocks, but it shouldn't 400
            expect(res.status).not.toBe(400);
        });

        it('should reject unknown keys (strict)', async () => {
            const req = createRequest({
                text: 'Hello world',
                engineVoiceId: 'en_US-lessac-high',
                extra: 'field'
            });
            const res = await VoicePreviewPOST(req);
            expect(res.status).toBe(400);
        });
    });
});

import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import { initializeTestEnvironment, RulesTestEnvironment, RulesTestContext } from '@firebase/rules-unit-testing';
import { setDoc, doc, getDoc, deleteDoc, setLogLevel } from 'firebase/firestore';
import * as fs from 'fs';
import * as path from 'path';

let testEnv: RulesTestEnvironment;
let aliceContext: RulesTestContext;
let bobContext: RulesTestContext;
let unauthContext: RulesTestContext;

const ALICE_UID = 'alice_uat';
const BOB_UID = 'bob_uat';
const PROJECT_ID = 'demo-uat-project';

beforeAll(async () => {
    // Read local rules file
    const rulesPath = path.resolve(__dirname, '../../firestore.rules');
    const rules = fs.readFileSync(rulesPath, 'utf8');

    // Mute verbose firestore logs
    setLogLevel('error');

    testEnv = await initializeTestEnvironment({
        projectId: PROJECT_ID,
        firestore: {
            rules,
            host: '127.0.0.1',
            port: 8080,
        },
    });

    aliceContext = testEnv.authenticatedContext(ALICE_UID);
    bobContext = testEnv.authenticatedContext(BOB_UID);
    unauthContext = testEnv.unauthenticatedContext();
});

afterAll(async () => {
    await testEnv.cleanup();
});

describe('Firestore Security Rules: Users Collection', () => {
    it('Denies unauthenticated read/write to users', async () => {
        const db = unauthContext.firestore();
        await expect(getDoc(doc(db, 'users', ALICE_UID))).rejects.toThrow();
        await expect(setDoc(doc(db, 'users', ALICE_UID), { test: true })).rejects.toThrow();
    });

    it('Allows authenticated user to write their own document', async () => {
        const db = aliceContext.firestore();
        await expect(setDoc(doc(db, 'users', ALICE_UID), { name: 'Alice' })).resolves.not.toThrow();
    });

    it('Denies cross-tenant write to users', async () => {
        const db = bobContext.firestore();
        await expect(setDoc(doc(db, 'users', ALICE_UID), { name: 'Bob Hacker' })).rejects.toThrow();
    });
});

describe('Firestore Security Rules: Projects Collection', () => {
    it('Allows user to create a project if uid matches', async () => {
        const db = aliceContext.firestore();
        await expect(setDoc(doc(db, 'projects', 'alice_proj'), { userId: ALICE_UID, title: 'Alice Book' })).resolves.not.toThrow();
    });

    it('Denies user creating a project with mismatched uid', async () => {
        const db = aliceContext.firestore();
        await expect(setDoc(doc(db, 'projects', 'alice_proj_fake2'), { userId: BOB_UID, title: 'Fake' })).rejects.toThrow();
    });

    it('Denies cross-tenant read of projects', async () => {
        const db = bobContext.firestore();
        await expect(getDoc(doc(db, 'projects', 'alice_proj'))).rejects.toThrow();
    });

    it('Denies unauthenticated read of projects', async () => {
        const db = unauthContext.firestore();
        await expect(getDoc(doc(db, 'projects', 'alice_proj'))).rejects.toThrow();
    });
});

describe('Firestore Security Rules: Subcollections (Chapters/Entities/Exports)', () => {
    it('Allows owner to create a chapter in their project', async () => {
        const db = aliceContext.firestore();
        await expect(setDoc(doc(db, 'chapters/ch1'), { userId: ALICE_UID, title: 'Chapter 1' })).resolves.not.toThrow();
    });

    it('Denies user from creating a chapter with mismatched userId', async () => {
        const db = bobContext.firestore();
        await expect(setDoc(doc(db, 'chapters/ch3_bob_fake'), { userId: ALICE_UID, title: 'Chapter 2' })).rejects.toThrow();
    });

    it('Allows owner to read their own chapter', async () => {
        const db = aliceContext.firestore();
        await expect(getDoc(doc(db, 'chapters/ch1'))).resolves.not.toThrow();
    });

    it('Denies non-owner from reading a chapter in another project', async () => {
        const db = bobContext.firestore();
        await expect(getDoc(doc(db, 'chapters/ch1'))).rejects.toThrow();
    });
});

describe('Firestore Security Rules: Voice Clones', () => {
    it('Allows owner to create and read voice clone', async () => {
        const db = aliceContext.firestore();
        await expect(setDoc(doc(db, `users/${ALICE_UID}/voices/voice1`), { status: 'ready' })).resolves.not.toThrow();
        await expect(getDoc(doc(db, `users/${ALICE_UID}/voices/voice1`))).resolves.not.toThrow();
    });

    it('Denies non-owner access to voice clone', async () => {
        const db = bobContext.firestore();
        await expect(getDoc(doc(db, `users/${ALICE_UID}/voices/voice1`))).rejects.toThrow();
        await expect(setDoc(doc(db, `users/${ALICE_UID}/voices/voice1_fake`), { status: 'hacked' })).rejects.toThrow();
    });
});

describe('Firestore Security Rules: Voice Catalog', () => {
    it('Denies unauthenticated read to voice_catalog', async () => {
        const db = unauthContext.firestore();
        await expect(getDoc(doc(db, 'voice_catalog', 'builtin1'))).rejects.toThrow();
    });

    it('Denies authenticated write to voice_catalog', async () => {
        const db = aliceContext.firestore();
        await expect(setDoc(doc(db, 'voice_catalog', 'builtin2'), { name: 'Hacked' })).rejects.toThrow();
    });
});

import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import { initializeTestEnvironment, RulesTestEnvironment, RulesTestContext } from '@firebase/rules-unit-testing';
import { getDoc, setDoc, doc, setLogLevel } from 'firebase/firestore';
import fs from 'fs';
import path from 'path';

let testEnv: RulesTestEnvironment;
let uatContext: RulesTestContext;
const PROJECT_ID = 'demo-uat-project';
const UID = 'uat-user-1';

beforeAll(async () => {
    // 1. Initialize Firestore Emulator Sandbox
    const rulesPath = path.resolve(__dirname, '../../firestore.rules');
    const rules = fs.readFileSync(rulesPath, 'utf8');
    setLogLevel('error');

    testEnv = await initializeTestEnvironment({
        projectId: PROJECT_ID,
        firestore: { rules, host: '127.0.0.1', port: 8080 },
    });
    uatContext = testEnv.authenticatedContext(UID);

    const originalFetch = globalThis.fetch;
    globalThis.fetch = async (...args) => {
        const urlStr = typeof args[0] === 'string' ? args[0] : (args[0] instanceof Request ? args[0].url : args[0].toString());
        const url = new URL(urlStr, 'http://localhost');
        const hostname = url.hostname;
        if (hostname === 'localhost' || hostname === '127.0.0.1' || hostname === 'host.docker.internal' || hostname === 'redis-uat' || hostname === 'firebase-emulators') {
            return originalFetch(...args);
        }
        throw new Error(`[UAT No-Egress Guard] Blocked external request to: ${urlStr}`);
    };
});

afterAll(async () => {
    await testEnv.cleanup();
});

describe('Token & Cost Monitor Integrity', () => {

    it('denies external network requests due to the global no-egress guard', async () => {
        // Just verify our global setup is working
        await expect(fetch('https://google.com')).rejects.toThrowError(/\[UAT No-Egress Guard\]/);
        await expect(fetch('https://api.openai.com/v1/chat')).rejects.toThrowError(/\[UAT No-Egress Guard\]/);
    });

    it('allows internal requests to local Ollama', async () => {
        // Technically this might fail if Ollama is not running, but it shouldn't throw the custom No Egress error.
        try {
            await fetch('http://host.docker.internal:11434');
        } catch (e: any) {
            expect(e.message).not.toContain('No-Egress Guard');
        }
    });

    it('logs token events correctly in Firestore', async () => {
        const db = uatContext.firestore();
        const eventId = 'token-event-1';

        // Simulating the backend hook `logTokenUsage`
        await setDoc(doc(db, `users/${UID}/token_events/${eventId}`), {
            timestamp: new Date().toISOString(),
            provider: 'ollama',
            model: 'phi3.5:3.8b-mini-instruct-q5_K_M',
            inputTokens: 100,
            outputTokens: 50,
            totalTokens: 150,
            cost: 0,
            valueSaved: 0.00075 // $5 per 1M local token value
        });

        const eventDoc = await getDoc(doc(db, `users/${UID}/token_events/${eventId}`));
        expect(eventDoc.exists()).toBe(true);
        expect(eventDoc.data()?.totalTokens).toEqual(150);
        expect(eventDoc.data()?.provider).toEqual('ollama');
    });
});

import { z } from 'zod';
import * as dotenv from 'dotenv';

const OLLAMA_URL = process.env.NEXT_PUBLIC_OLLAMA_URL || 'http://127.0.0.1:11434';
const JUDGE_MODEL = 'qwen3.5:9b';

export async function evaluateLLM<T>(
    systemInstruction: string,
    prompt: string,
    schema: z.ZodSchema<T>
): Promise<T> {

    // First attempt
    const rawResponse = await callOllama(systemInstruction, prompt);
    console.log(`[LLM Judge] Raw response (1st): ${rawResponse.substring(0, 100)}...`);

    try {
        // Parse and validate
        const parsed = JSON.parse(rawResponse);
        return schema.parse(parsed);
    } catch (e: any) {
        console.warn(`[LLM Judge] First validation failed. Retrying... Error: ${e.message}`);

        // Retry attempt / Repair JSON
        const repairPrompt = `
You previously returned this JSON:
${rawResponse}

It failed validation with this error:
${e.message}

Please repair the JSON so that it perfectly matches the required schema. Return ONLY the raw valid JSON object. Do not wrap it in markdown blockquotes.
`;

        const retryResponse = await callOllama("You are a strict JSON repair bot.", repairPrompt);
        console.log(`[LLM Judge] Raw response (retry): ${retryResponse.substring(0, 100)}...`);
        const retryParsed = JSON.parse(retryResponse);
        return schema.parse(retryParsed);
    }
}

async function callOllama(system: string, prompt: string): Promise<string> {
    const res = await fetch(`${OLLAMA_URL}/api/generate`, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json'
        },
        body: JSON.stringify({
            model: JUDGE_MODEL,
            system: system,
            prompt: prompt,
            format: 'json',
            stream: false,
            options: {
                temperature: 0.1
            }
        })
    });

    if (!res.ok) {
        const err = await res.text();
        throw new Error(`Ollama API returned ${res.status}: ${err}`);
    }

    const data = await res.json();
    return data.response;
}

